import React, { useState, useMemo } from 'react';
import { Calculator, Home, Info, ShieldCheck, Truck, Package, Warehouse, ArrowRight } from 'lucide-react';
import { CALCULATOR_OPTIONS } from '../constants';

interface QuickQuoteCalculatorProps {
  onRequestFullQuote: () => void;
}

const QuickQuoteCalculator: React.FC<QuickQuoteCalculatorProps> = ({ onRequestFullQuote }) => {
  const [propertySize, setPropertySize] = useState(CALCULATOR_OPTIONS.propertySizes[1].id);
  const [ukRegion, setUkRegion] = useState(CALCULATOR_OPTIONS.ukRegions[0].id);
  const [spainRegion, setSpainRegion] = useState(CALCULATOR_OPTIONS.spainRegions[0].id);
  const [moveType, setMoveType] = useState<'dedicated' | 'shared'>('dedicated');
  const [extras, setExtras] = useState<string[]>([]);

  const totalEstimate = useMemo(() => {
    const size = CALCULATOR_OPTIONS.propertySizes.find(s => s.id === propertySize);
    const uk = CALCULATOR_OPTIONS.ukRegions.find(r => r.id === ukRegion);
    const spain = CALCULATOR_OPTIONS.spainRegions.find(r => r.id === spainRegion);

    if (!size || !uk || !spain) return 0;

    let base = size.basePrice;

    // Move Type logic
    if (moveType === 'shared') {
      base = base * 0.65; // Shared load discount
    }

    // Regional adjustments
    base += uk.offset;
    base += spain.offset;

    // Extras logic
    if (extras.includes('packing')) {
      const bedCount = parseInt(propertySize.charAt(0)) || 1;
      base += bedCount * 200;
    }
    if (extras.includes('storage')) base += 180;
    if (extras.includes('insurance')) base += 120;

    return Math.round(base);
  }, [propertySize, ukRegion, spainRegion, moveType, extras]);

  const toggleExtra = (id: string) => {
    setExtras(prev => prev.includes(id) ? prev.filter(e => e !== id) : [...prev, id]);
  };

  return (
    <section className="py-24 bg-slate-900 text-white overflow-hidden">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col lg:flex-row gap-16 items-center">

          <div className="lg:w-1/2 space-y-8">
            <div>
              <div className="inline-flex items-center space-x-2 bg-blue-500/10 text-blue-400 px-4 py-2 rounded-full text-sm font-bold mb-6">
                <Calculator size={16} />
                <span>Instant Estimator</span>
              </div>
              <h2 className="text-4xl md:text-5xl font-bold mb-6">Quick Quote Calculator</h2>
              <p className="text-slate-400 text-lg leading-relaxed">
                Get a transparent, instant estimate for your relocation to Spain. Our calculator uses real-time data from our weekly routes to give you the most accurate starting price.
              </p>
            </div>

            <div className="space-y-6">
              {/* Move Type */}
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMoveType('dedicated')}
                  className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center text-center space-y-2 ${moveType === 'dedicated' ? 'border-blue-500 bg-blue-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-700'}`}
                >
                  <Truck className={moveType === 'dedicated' ? 'text-blue-400' : 'text-slate-500'} />
                  <span className="font-bold block">Dedicated Load</span>
                  <span className="text-xs text-slate-500">Fastest & Direct</span>
                </button>
                <button 
                  onClick={() => setMoveType('shared')}
                  className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center text-center space-y-2 ${moveType === 'shared' ? 'border-blue-500 bg-blue-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-700'}`}
                >
                  <Package className={moveType === 'shared' ? 'text-blue-400' : 'text-slate-500'} />
                  <span className="font-bold block">Shared Load</span>
                  <span className="text-xs text-slate-500">Cost-Effective</span>
                </button>
              </div>

              {/* Property Size */}
              <div className="space-y-3">
                <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Property Size</label>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                  {CALCULATOR_OPTIONS.propertySizes.map(size => (
                    <button
                      key={size.id}
                      onClick={() => setPropertySize(size.id)}
                      className={`py-3 px-2 rounded-xl border text-sm font-bold transition-all ${propertySize === size.id ? 'bg-white text-slate-900 border-white' : 'border-slate-800 text-slate-400 hover:border-slate-600'}`}
                    >
                      {size.label.split(' ')[0]} {size.label.split(' ')[1]}
                    </button>
                  ))}
                </div>
              </div>

              {/* Regions */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">UK Origin</label>
                  <select 
                    value={ukRegion}
                    onChange={(e) => setUkRegion(e.target.value)}
                    className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    {CALCULATOR_OPTIONS.ukRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Spain Destination</label>
                  <select 
                    value={spainRegion}
                    onChange={(e) => setSpainRegion(e.target.value)}
                    className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    {CALCULATOR_OPTIONS.spainRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 w-full">
            <div className="bg-white rounded-[2rem] p-8 md:p-12 text-slate-900 shadow-2xl relative">
              <div className="absolute top-0 right-10 -translate-y-1/2 bg-blue-600 text-white px-6 py-2 rounded-full font-bold shadow-lg flex items-center space-x-2">
                <ShieldCheck size={18} />
                <span>Customs Included</span>
              </div>

              <div className="mb-8">
                <p className="text-slate-500 font-bold uppercase tracking-widest text-sm mb-2">Estimated Total</p>
                <div className="flex items-baseline space-x-2">
                  <span className="text-5xl md:text-7xl font-black text-blue-600 tracking-tighter">£{totalEstimate.toLocaleString()}</span>
                  <span className="text-slate-400 font-medium">GBP*</span>
                </div>
              </div>

              <div className="space-y-4 mb-10 border-t border-slate-100 pt-8">
                <p className="font-bold text-slate-900">Recommended Extras:</p>
                {CALCULATOR_OPTIONS.services.map(service => (
                  <label key={service.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl cursor-pointer hover:bg-slate-100 transition-colors">
                    <div className="flex items-center space-x-4">
                      <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${extras.includes(service.id) ? 'bg-blue-600 border-blue-600' : 'border-slate-300'}`}>
                        {extras.includes(service.id) && <div className="w-2 h-2 bg-white rounded-full"></div>}
                      </div>
                      <span className="font-medium text-slate-700">{service.label}</span>
                    </div>
                    <input 
                      type="checkbox" 
                      className="hidden" 
                      checked={extras.includes(service.id)}
                      onChange={() => toggleExtra(service.id)}
                    />
                    <span className="text-slate-400 text-sm font-bold">
                      {service.id === 'packing' ? `+£${(parseInt(propertySize.charAt(0)) || 1) * 200}` : `+£${service.price}`}
                    </span>
                  </label>
                ))}
              </div>

              <button 
                onClick={onRequestFullQuote}
                className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold text-lg hover:bg-blue-600 transition-all transform hover:scale-[1.02] shadow-xl flex items-center justify-center space-x-3"
              >
                <span>Proceed to Final Quote</span>
                <ArrowRight size={20} />
              </button>

              <div className="mt-8 flex items-start space-x-3 p-4 bg-blue-50 rounded-xl">
                <Info size={18} className="text-blue-600 shrink-0 mt-0.5" />
                <p className="text-xs text-slate-600 leading-relaxed">
                  *This estimate is based on standard accessibility and volume. Final pricing is subject to a professional video survey or physical inspection of goods and documentation requirements.
                </p>
              </div>
            </div>
          </div>

        </div>
      </div>
    </section>
  );
};

export default QuickQuoteCalculator;

