import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import DetailedServices from './components/DetailedServices';
import QuickQuoteCalculator from './components/QuickQuoteCalculator';
import Testimonials from './components/Testimonials';
import FAQ from './components/FAQ';
import ContactSection from './components/ContactSection';
import Footer from './components/Footer';
import QuoteModal from './components/QuoteModal';

type View = 'home' | 'quote';

const App: React.FC = () => {
  const [view, setView] = useState<View>('home');
  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);

  // Scroll to top when view changes
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [view]);

  const navigateTo = (newView: View) => {
    setView(newView);
    setIsQuoteModalOpen(false);
  };

  const openQuoteModal = () => {
    // Instead of a modal, we now navigate to the dedicated page
    navigateTo('quote');
  };

  const closeQuoteModal = () => setIsQuoteModalOpen(false);

  return (
    <div className="flex flex-col min-h-screen">
      <Header onNavigate={navigateTo} currentView={view} />

      <main className="flex-grow">
        {view === 'home' ? (
          <>
            <Hero onOpenQuote={() => navigateTo('quote')} />
            <DetailedServices />
            <Testimonials />
            <FAQ />
            <ContactSection />
          </>
        ) : (
          <div className="pt-20">
            <QuickQuoteCalculator onRequestFullQuote={() => setIsQuoteModalOpen(true)} />
          </div>
        )}
      </main>

      <Footer onNavigate={navigateTo} />

      {/* Quote Modal preserved for the "Request Full Quote" step in the calculator */}
      <QuoteModal isOpen={isQuoteModalOpen} onClose={closeQuoteModal} />
    </div>
  );
};

export default App;

