                  >
                    {CALCULATOR_OPTIONS.ukRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Spain Destination</label>
                  <select 
                    value={spainRegion}
                    onChange={(e) => setSpainRegion(e.target.value)}
                    className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    {CALCULATOR_OPTIONS.spainRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3 sm:col-span-2">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Desired Move Date</label>
                  <div className="relative">
                    <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                    <input 
