import React, { useState, useEffect, useMemo } from 'react';
import { 
  Lock, ShieldCheck, ChevronRight, Users, TrendingUp, 
  Package, Calendar, CheckCircle, Clock, Trash2, 
  Search, Filter, Download, LayoutDashboard, Database, AlertCircle, RefreshCw
} from 'lucide-react';

interface SavedQuote {
  ref: string;
  email: string;
  volume: number;
  price: number;
  date: string;
  status: string;
  origin: string;
  destination: string;
  timestamp?: number;
}

const AdminPortal: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [quotes, setQuotes] = useState<SavedQuote[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState<'dashboard' | 'quotes' | 'database'>('dashboard');

  useEffect(() => {
    if (isAuthenticated) {
      loadQuotes();
    }
  }, [isAuthenticated]);

  const loadQuotes = () => {
    const saved = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
    setQuotes(saved.reverse()); // Newest first
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    // Simulation of admin credentials check
    setTimeout(() => {
      if (password === 'admin123') {
        setIsAuthenticated(true);
      } else {
        alert('Invalid admin password');
      }
      setLoading(false);
    }, 800);
  };

  const updateQuoteStatus = (ref: string, newStatus: string) => {
    const updated = quotes.map(q => q.ref === ref ? { ...q, status: newStatus } : q);
    setQuotes(updated);
    localStorage.setItem('britons_saved_quotes', JSON.stringify(updated.slice().reverse()));
  };

  const deleteQuote = (ref: string) => {
    if (confirm('Are you sure you want to delete this quote record?')) {
      const updated = quotes.filter(q => q.ref !== ref);
      setQuotes(updated);
      localStorage.setItem('britons_saved_quotes', JSON.stringify(updated.slice().reverse()));
    }
  };

  const filteredQuotes = useMemo(() => {
    return quotes.filter(q => 
      q.ref.toLowerCase().includes(searchTerm.toLowerCase()) || 
      q.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      q.destination.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [quotes, searchTerm]);

  const stats = useMemo(() => {
    return {
      totalQuotes: quotes.length,
      totalVolume: Math.round(quotes.reduce((acc, curr) => acc + curr.volume, 0)),
      totalPotentialRevenue: Math.round(quotes.reduce((acc, curr) => acc + curr.price, 0)),
      acceptedMoves: quotes.filter(q => q.status === 'Quote Accepted').length
    };
  }, [quotes]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center bg-slate-900 px-4 py-12">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-8 md:p-12 border border-slate-200">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-slate-100 text-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 border-2 border-slate-200">
              <Lock size={32} />
            </div>
            <h2 className="text-3xl font-bold text-slate-900">Admin Login</h2>
            <p className="text-slate-500 mt-2 text-sm">Staff portal for Briton's Removals</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Administrator Password</label>
              <input 
                required
                type="password" 
                placeholder="••••••••"
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-slate-900 outline-none transition-all"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>
            <button 
              type="submit"
              disabled={loading}
              className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2"
            >
              {loading ? <RefreshCw className="animate-spin" /> : <span>Access Admin Console</span>}
            </button>
          </form>
          <p className="text-center text-[10px] text-slate-400 mt-6 font-bold uppercase tracking-widest">Authorized Access Only</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Admin Header */}
      <div className="bg-slate-900 text-white pt-8 pb-32">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div className="flex items-center space-x-4">
              <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center border border-white/20">
                <ShieldCheck size={28} className="text-blue-400" />
              </div>
              <div>
                <h2 className="text-3xl font-black tracking-tight">Admin Console</h2>
                <div className="flex items-center space-x-2 text-slate-400 text-xs font-bold uppercase tracking-widest">
                  <span className="w-2 h-2 bg-green-500 rounded-full"></span>
                  <span>System Live</span>
                </div>
              </div>
            </div>
            <div className="flex items-center space-x-3">
              <button 
                onClick={loadQuotes}
                className="p-3 bg-white/5 rounded-xl border border-white/10 hover:bg-white/10 transition-colors"
                title="Refresh Data"
              >
                <RefreshCw size={20} />
              </button>
              <button 
                onClick={() => setIsAuthenticated(false)}
                className="px-6 py-3 bg-red-600/20 text-red-400 border border-red-600/30 rounded-xl font-bold hover:bg-red-600 hover:text-white transition-all"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-20">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">

          {/* Stats Bar */}
          <div className="lg:col-span-4 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 flex items-center space-x-4">
               <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><TrendingUp size={24} /></div>
               <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Potential Revenue</p>
                  <p className="text-2xl font-black text-slate-900">£{stats.totalPotentialRevenue.toLocaleString()}</p>
               </div>
            </div>
            <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 flex items-center space-x-4">
               <div className="p-3 bg-green-50 text-green-600 rounded-2xl"><Package size={24} /></div>
               <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Total Volume (m³)</p>
                  <p className="text-2xl font-black text-slate-900">{stats.totalVolume.toLocaleString()}</p>
               </div>
            </div>
            <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 flex items-center space-x-4">
               <div className="p-3 bg-purple-50 text-purple-600 rounded-2xl"><CheckCircle size={24} /></div>
               <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Accepted Moves</p>
                  <p className="text-2xl font-black text-slate-900">{stats.acceptedMoves}</p>
               </div>
            </div>
            <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 flex items-center space-x-4">
               <div className="p-3 bg-amber-50 text-amber-600 rounded-2xl"><Users size={24} /></div>
               <div>
                  <p className="text-xs font-bold text-slate-400 uppercase">Total Saved Quotes</p>
                  <p className="text-2xl font-black text-slate-900">{stats.totalQuotes}</p>
               </div>
            </div>
          </div>

          {/* Sidebar Nav */}
          <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 h-fit space-y-1">
            <button 
              onClick={() => setActiveTab('dashboard')}
              className={`w-full flex items-center space-x-3 px-4 py-4 rounded-2xl font-bold transition-all ${activeTab === 'dashboard' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <LayoutDashboard size={20} />
              <span>Dashboard</span>
            </button>
            <button 
              onClick={() => setActiveTab('quotes')}
              className={`w-full flex items-center space-x-3 px-4 py-4 rounded-2xl font-bold transition-all ${activeTab === 'quotes' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <Calendar size={20} />
              <span>Manage Quotes</span>
              {stats.totalQuotes > 0 && <span className="bg-blue-600 text-white text-[10px] px-2 py-1 rounded-full">{stats.totalQuotes}</span>}
            </button>
            <button 
              onClick={() => setActiveTab('database')}
              className={`w-full flex items-center space-x-3 px-4 py-4 rounded-2xl font-bold transition-all ${activeTab === 'database' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <Database size={20} />
              <span>System Backup</span>
            </button>
          </div>

          {/* Main Content Area */}
          <div className="lg:col-span-3 bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden min-h-[600px]">
            {activeTab === 'quotes' && (
              <div className="animate-fade-in p-8">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                   <h3 className="text-2xl font-black text-slate-900">Saved System Quotes</h3>
                   <div className="flex items-center space-x-2 w-full md:w-auto">
                      <div className="relative flex-grow md:w-64">
                         <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                         <input 
                          type="text" 
                          placeholder="Search Ref or Email..."
                          className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-slate-900 outline-none"
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                         />
