            )}

            {activeTab === 'dashboard' && (
              <div className="p-8 animate-fade-in space-y-8">
                 <div className="flex justify-between items-center">
                    <h3 className="text-2xl font-black text-slate-900">Operations Summary</h3>
                    <p className="text-xs text-slate-400 font-bold uppercase">Real-time Metrics</p>
