                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100">
                       <h4 className="font-black text-slate-900 mb-4 flex items-center space-x-2">
                          <CheckCircle size={18} className="text-green-600" />
                          <span>Conversion Rate</span>
                       </h4>
                       <div className="flex items-baseline space-x-2 mb-6">
                          <span className="text-4xl font-black text-slate-900">{stats.totalQuotes > 0 ? Math.round((stats.acceptedMoves / stats.totalQuotes) * 100) : 0}%</span>
                          <span className="text-slate-400 font-bold">of quotes saved</span>
                       </div>
                       <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden">
                          <div 
                            className="bg-green-500 h-full transition-all duration-1000" 
                            style={{ width: `${stats.totalQuotes > 0 ? (stats.acceptedMoves / stats.totalQuotes) * 100 : 0}%` }}
                          />
                       </div>
                    </div>

                    <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100">
                       <h4 className="font-black text-slate-900 mb-4 flex items-center space-x-2">
                          <Clock size={18} className="text-amber-600" />
                          <span>Upcoming Departures</span>
                       </h4>
                       <div className="space-y-4">
                          {quotes.filter(q => q.status === 'Quote Accepted').slice(0, 3).map(q => (
                            <div key={q.ref} className="flex justify-between items-center bg-white p-3 rounded-xl shadow-sm border border-slate-100">
                               <div>
                                  <p className="text-xs font-black text-slate-900">{q.destination}</p>
                                  <p className="text-[10px] text-slate-400 font-bold">{q.date}</p>
                               </div>
                               <span className="font-mono text-[10px] font-black text-blue-600">{q.ref}</span>
                            </div>
                          ))}
                          {quotes.filter(q => q.status === 'Quote Accepted').length === 0 && (
                            <p className="text-xs text-slate-400 italic">No accepted moves pending departure.</p>
