                 <div className="p-8 bg-blue-900 text-white rounded-[2rem] relative overflow-hidden shadow-2xl">
                    <TrendingUp className="absolute -bottom-10 -right-10 w-48 h-48 opacity-10" />
                    <div className="relative z-10">
                       <h4 className="text-xl font-bold mb-2">Market Insight: UK to Spain</h4>
                       <p className="text-blue-200 text-sm leading-relaxed max-w-xl">
                          Current trends show a 15% increase in removals to the Costa Blanca region this quarter. Logistics optimization suggests consolidating part-loads for Murcia on Friday runs.
                       </p>
                    </div>
                 </div>
              </div>
            )}

            {activeTab === 'database' && (
              <div className="p-8 animate-fade-in flex flex-col items-center justify-center text-center py-20">
                 <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                    <Database size={40} className="text-slate-400" />
                 </div>
                 <h3 className="text-2xl font-black text-slate-900 mb-2">System Database Management</h3>
