                <ShieldCheck size={28} className="text-blue-400" />
              </div>
              <div>
                <h2 className="text-3xl font-black tracking-tight">Admin Console</h2>
                <div className="flex items-center space-x-2 text-slate-400 text-xs font-bold uppercase tracking-widest">
                  <span className="w-2 h-2 bg-green-500 rounded-full"></span>
                  <span>System Live</span>
                </div>
              </div>
            </div>
            <div className="flex items-center space-x-3">
              <button 
                onClick={loadQuotes}
                className="p-3 bg-white/5 rounded-xl border border-white/10 hover:bg-white/10 transition-colors"
                title="Refresh Data"
              >
                <RefreshCw size={20} />
              </button>
              <button 
                onClick={() => setIsAuthenticated(false)}
                className="px-6 py-3 bg-red-600/20 text-red-400 border border-red-600/30 rounded-xl font-bold hover:bg-red-600 hover:text-white transition-all"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-20">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 pb-24">

          {/* Stats Bar */}
          <div className="lg:col-span-4 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
