                <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100 flex items-start space-x-4">
                   <ShieldCheck className="text-blue-600 mt-1" size={24} />
                   <div className="text-sm text-blue-800 leading-relaxed">
                     <strong>Customs Notice:</strong> Please declare all items as honestly as possible. Used household effects older than 6 months are typically exempt from IVA if residency is proven.
                     <a href="#" className="flex items-center text-blue-600 font-bold mt-1 hover:underline">
