                <div className="grid grid-cols-1 gap-4">
                  {documents.map(doc => (
                    <div 
                      key={doc.id} 
                      className={`p-6 rounded-3xl border transition-all flex flex-col md:flex-row items-center justify-between gap-6 ${
                        doc.status === 'required' ? 'bg-white border-slate-200' : 
                        doc.status === 'pending' ? 'bg-blue-50 border-blue-200' : 'bg-green-50 border-green-200'
                      }`}
                    >
                      <div className="flex items-center space-x-4">
                        <div className={`p-3 rounded-2xl ${
                          doc.status === 'required' ? 'bg-slate-100 text-slate-400' : 
                          doc.status === 'pending' ? 'bg-blue-100 text-blue-600' : 'bg-green-100 text-green-600'
                        }`}>
                          <File size={24} />
                        </div>
                        <div>
                          <h4 className="font-bold text-slate-900">{doc.name}</h4>
                          {doc.fileName ? (
                            <p className="text-xs text-slate-500 font-medium">Uploaded: {doc.fileName} ({doc.uploadDate})</p>
                          ) : (
                            <p className="text-xs text-slate-400 uppercase font-black tracking-widest mt-1">File Required</p>
                          )}
                        </div>
                      </div>

                      <div className="flex items-center space-x-3 w-full md:w-auto">
                        {doc.status === 'required' ? (
                          <label className="flex-grow md:flex-grow-0 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-bold text-sm cursor-pointer transition-all flex items-center justify-center space-x-2 shadow-lg">
                            {isUploading === doc.id ? (
                              <Loader2 size={18} className="animate-spin" />
                            ) : (
                              <Upload size={18} />
                            )}
                            <span>{isUploading === doc.id ? 'Uploading...' : 'Upload File'}</span>
                            <input 
                              type="file" 
                              className="hidden" 
                              onChange={(e) => handleFileUpload(doc.id, e)}
                              accept=".pdf,.jpg,.jpeg,.png"
                              disabled={isUploading !== null}
                            />
                          </label>
                        ) : (
                          <div className="flex items-center space-x-2">
                             <div className={`flex items-center space-x-1.5 px-3 py-1.5 rounded-lg text-xs font-bold uppercase ${
                               doc.status === 'pending' ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'
                             }`}>
                                {doc.status === 'pending' ? <Clock size={14} /> : <CheckCircle2 size={14} />}
                                <span>{doc.status}</span>
                             </div>
                             <button 
                              onClick={() => removeFile(doc.id)}
                              className="p-2.5 text-slate-400 hover:text-red-500 bg-white border border-slate-200 rounded-xl transition-colors"
                              title="Remove document"
                             >
                               <Trash2 size={16} />
                             </button>
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>

                <div className="p-8 bg-slate-900 text-white rounded-[2rem] relative overflow-hidden shadow-2xl">
                   <div className="relative z-10 flex flex-col md:flex-row items-center gap-8">
                      <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shrink-0">
                         <ShieldCheck size={32} />
                      </div>
                      <div>
                        <h4 className="text-xl font-black mb-2">GDPR & Security Commitment</h4>
                        <p className="text-slate-400 text-sm leading-relaxed max-w-2xl">
                          All sensitive documents are encrypted during transit and stored on our secure UK servers. Access is strictly limited to our authorized customs agents and your dedicated move coordinator.
                        </p>
                      </div>
                   </div>
                </div>
              </div>
            )}

            {activeTab === 'messages' && (
              <div className="flex flex-col h-full max-h-[600px] animate-fade-in">
                <div className="flex items-center justify-between mb-6 pb-4 border-b border-slate-100">
                   <h3 className="text-2xl font-bold text-slate-900">Coordinator Chat</h3>
                   <div className="flex items-center space-x-2">
                      <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                      <span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Mark is online</span>
                   </div>
                </div>

                <div className="flex-grow overflow-y-auto pr-4 space-y-4 custom-scrollbar mb-6 min-h-[300px]">
                   {messages.map(msg => (
                     <div key={msg.id} className={`flex flex-col ${msg.sender === 'client' ? 'items-end' : 'items-start'}`}>
                        <div className={`max-w-[80%] px-4 py-3 rounded-2xl text-sm ${msg.sender === 'client' ? 'bg-blue-600 text-white rounded-br-none' : 'bg-slate-100 text-slate-800 rounded-bl-none'}`}>
                           {msg.text}
                        </div>
                        <span className="text-[10px] text-slate-400 mt-1 font-bold">{msg.timestamp}</span>
                     </div>
                   ))}
                </div>

                <form onSubmit={handleSendMessage} className="flex items-center space-x-3 bg-slate-50 p-2 rounded-2xl border border-slate-200">
                   <input 
                    type="text" 
                    placeholder="Type your message to Mark..."
                    className="flex-grow bg-transparent px-4 py-2 outline-none text-slate-800"
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                   />
                   <button 
                    type="submit"
                    className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-colors shadow-lg"
                   >
                     <Send size={18} />
                   </button>
                </form>
              </div>
            )}
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default YourMove;

import React, { useState, useEffect } from 'react';
import { 
  Lock, CheckCircle2, Truck, ClipboardList, MessageSquare, 
  Calendar, FileText, Send, Plus, Trash2, AlertCircle, 
  ChevronRight, MapPin, Package, ShieldCheck, UserCircle, History, ExternalLink,
  Upload, FileCheck, File, X, Loader2, Clock
} from 'lucide-react';
import { COMPANY_INFO } from '../constants';

interface ItineraryItem {
  id: string;
  description: string;
  value: string;
  boxNumber?: string;
}

interface Message {
  id: string;
  text: string;
  sender: 'client' | 'agent';
  timestamp: string;
}

interface SavedQuote {
  ref: string;
  email: string;
  volume: number;
  price: number;
  date: string;
  status: string;
  origin: string;
  destination: string;
}

interface UserDocument {
  id: string;
  name: string;
  status: 'required' | 'pending' | 'approved' | 'rejected';
  fileName?: string;
  uploadDate?: string;
}

const YourMove: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [reference, setReference] = useState('');
  const [surname, setSurname] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Data for the current active move (from saved quote if applicable)
  const [activeMoveData, setActiveMoveData] = useState<SavedQuote | null>(null);

  // Dashboard Data State
  const [activeTab, setActiveTab] = useState<'overview' | 'customs' | 'documents' | 'messages'>('overview');
  const [itinerary, setItinerary] = useState<ItineraryItem[]>([
    { id: '1', description: 'Kitchenware (Standard Boxes)', value: '£400', boxNumber: '1-4' },
    { id: '2', description: 'Dining Room Table (Wrapped)', value: '£800', boxNumber: '7' },
  ]);
  const [newItem, setNewItem] = useState({ description: '', value: '', boxNumber: '' });

  const [messages, setMessages] = useState<Message[]>([
    { id: '1', sender: 'agent', text: 'Hello! Welcome to your move portal. I am your coordinator, Mark. We have confirmed your loading for the 15th.', timestamp: '10:15 AM' },
    { id: '2', sender: 'client', text: 'Thank you Mark. Can I update the customs list until tomorrow?', timestamp: '11:20 AM' },
    { id: '3', sender: 'agent', text: 'Yes, of course. Please ensure all values are in GBP for the T1 document.', timestamp: '11:25 AM' },
  ]);
  const [newMessage, setNewMessage] = useState('');

  // Documents State
  const [documents, setDocuments] = useState<UserDocument[]>([
    { id: 'doc-1', name: 'Lead Passenger Passport', status: 'required' },
    { id: 'doc-2', name: 'T1 Customs Declaration Form', status: 'required' },
    { id: 'doc-3', name: 'Spanish Residency Proof (TIE/NIE)', status: 'required' },
    { id: 'doc-4', name: 'Proof of UK Address (Council Tax/Utility)', status: 'required' },
  ]);
  const [isUploading, setIsUploading] = useState<string | null>(null);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Simulate API call and check local storage for saved quotes
    setTimeout(() => {
      const savedQuotes: SavedQuote[] = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
      const foundQuote = savedQuotes.find(q => q.ref.toUpperCase() === reference.toUpperCase());

      // Allow the default mock reference ESP-12345 or any saved quote
      if (reference.toUpperCase() === 'ESP-12345' || foundQuote) {
        if (foundQuote) {
          setActiveMoveData(foundQuote);
        }
        setIsAuthenticated(true);
      } else {
        setError('Reference not found. Please check your quote email.');
      }
      setLoading(false);
    }, 1200);
  };

  const handleAddItem = () => {
    if (newItem.description && newItem.value) {
      setItinerary([...itinerary, { ...newItem, id: Date.now().toString() }]);
      setNewItem({ description: '', value: '', boxNumber: '' });
    }
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (newMessage.trim()) {
      const msg: Message = {
        id: Date.now().toString(),
        sender: 'client',
        text: newMessage,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };
      setMessages([...messages, msg]);
      setNewMessage('');
    }
  };

  const handleFileUpload = (docId: string, event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsUploading(docId);

    // Simulate upload delay
    setTimeout(() => {
      setDocuments(prev => prev.map(doc => {
        if (doc.id === docId) {
          return {
            ...doc,
            status: 'pending',
            fileName: file.name,
            uploadDate: new Date().toLocaleDateString()
          };
        }
        return doc;
      }));
      setIsUploading(null);
    }, 1500);
  };

  const removeFile = (docId: string) => {
    setDocuments(prev => prev.map(doc => {
      if (doc.id === docId) {
        return { ...doc, status: 'required', fileName: undefined, uploadDate: undefined };
      }
      return doc;
    }));
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center bg-slate-50 px-4 py-12">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 border border-slate-100">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
              {/* Fix: Changed 'lock' to 'Lock' to match the imported component name from lucide-react */}
              <Lock size={32} />
            </div>
            <h2 className="text-3xl font-bold text-slate-900">Your Move Portal</h2>
            <p className="text-slate-500 mt-2 text-sm">Enter your quote reference or move ID</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Move Reference</label>
              <input 
                required
                type="text" 
                placeholder="e.g. ESP-12345"
                className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all ${error ? 'border-red-500' : 'border-slate-200'}`}
                value={reference}
                onChange={(e) => setReference(e.target.value)}
              />
              {error && <p className="text-red-500 text-[10px] font-bold mt-1 uppercase tracking-wider">{error}</p>}
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Lead Surname / Email</label>
              <input 
                required
                type="text" 
                placeholder="Enter your registered name"
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                value={surname}
                onChange={(e) => setSurname(e.target.value)}
              />
            </div>
            <button 
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2"
            >
              {loading ? (
                <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  <span>Access Dashboard</span>
                  <ChevronRight size={18} />
                </>
              )}
            </button>
          </form>

          <div className="mt-8 p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
             <p className="text-[10px] text-slate-400 font-bold uppercase text-center mb-2">Helpful Tip</p>
             <p className="text-[10px] text-slate-600 leading-relaxed text-center">
               Don't have a reference? Use the <span className="text-blue-600 font-bold">Quick Quote Calculator</span> and click 'Save Quote' to generate a reference instantly.
             </p>
          </div>

          <div className="mt-8 pt-8 border-t border-slate-100 text-center">
            <p className="text-slate-500 text-xs flex items-center justify-center space-x-2">
              <ShieldCheck size={14} className="text-green-500" />
              <span>Secure Encrypted Connection</span>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      {/* Dashboard Header */}
      <div className="bg-slate-900 text-white pt-12 pb-24">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center space-x-3 text-blue-400 text-sm font-bold uppercase tracking-widest mb-2">
                <Truck size={16} />
                <span>Reference: {reference || activeMoveData?.ref || 'ESP-48291'}</span>
              </div>
              <h2 className="text-4xl font-black">Hello, {surname || 'Valued Customer'}</h2>
              <p className="text-slate-400 mt-2">
                Your relocation to <span className="text-white font-bold">{activeMoveData?.destination || 'Alicante, Spain'}</span> is 
                {activeMoveData ? ' saved and ready for booking.' : ' currently in progress.'}
              </p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="bg-white/10 p-4 rounded-2xl border border-white/10 backdrop-blur-md">
                 <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-1">Target Date</p>
                 <p className="text-xl font-black">{activeMoveData?.date ? new Date(activeMoveData.date).toLocaleDateString() : '15th May 2024'}</p>
              </div>
              <div className="bg-blue-600 p-4 rounded-2xl border border-blue-500 shadow-xl">
                 <p className="text-xs text-blue-100 font-bold uppercase tracking-widest mb-1">Status</p>
                 <p className="text-xl font-black">{activeMoveData?.status || 'In Preparation'}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-12">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden min-h-[600px] flex flex-col md:flex-row">

          {/* Sidebar Nav */}
          <div className="w-full md:w-64 bg-slate-50 border-r border-slate-100 p-6 space-y-2">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}
            >
              <Package size={20} />
              <span>Overview</span>
            </button>
            <button 
              onClick={() => setActiveTab('customs')}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'customs' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}
            >
              <ClipboardList size={20} />
              <span>Customs List</span>
            </button>
            <button 
              onClick={() => setActiveTab('documents')}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'documents' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}
            >
              <FileCheck size={20} />
              <span>Documents</span>
