  quantity: number;
}

const QuickQuoteCalculator: React.FC<QuickQuoteCalculatorProps> = ({ onRequestFullQuote }) => {
  const [calculationMode, setCalculationMode] = useState<'size' | 'inventory'>('size');
  const [propertySize, setPropertySize] = useState(CALCULATOR_OPTIONS.propertySizes[1].id);
  const [ukRegion, setUkRegion] = useState(CALCULATOR_OPTIONS.ukRegions[0].id);
  const [spainRegion, setSpainRegion] = useState(CALCULATOR_OPTIONS.spainRegions[0].id);
  const [moveType, setMoveType] = useState<'dedicated' | 'shared'>('dedicated');
  const [moveDate, setMoveDate] = useState('');
  const [extras, setExtras] = useState<string[]>([]);
  const [inventory, setInventory] = useState<Record<string, number>>({});
  const [customItems, setCustomItems] = useState<CustomItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<string | null>(INVENTORY_CATEGORIES[0].id);

  // Save Quote State
  const [isSaving, setIsSaving] = useState(false);
  const [email, setEmail] = useState('');
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [generatedRef, setGeneratedRef] = useState('');

  // Custom item input state
  const [newCustomLabel, setNewCustomLabel] = useState('');
  const [newCustomVolume, setNewCustomVolume] = useState<number | ''>('');

  // Calculate minimum move date
  const minMoveDate = useMemo(() => {
    const date = new Date();
    date.setDate(date.getDate() + 14);
    return date.toISOString().split('T')[0];
  }, []);

  const totalVolume = useMemo(() => {
    if (calculationMode === 'size') {
      const size = CALCULATOR_OPTIONS.propertySizes.find(s => s.id === propertySize);
      return size?.estVolume || 0;
    } else {
      let volume = 0;
      INVENTORY_CATEGORIES.forEach(cat => {
        cat.items.forEach(item => {
          if (inventory[item.id]) {
            volume += inventory[item.id] * item.volume;
          }
        });
      });
      customItems.forEach(item => {
        volume += item.quantity * item.volume;
      });
      return parseFloat(volume.toFixed(2));
    }
  }, [calculationMode, propertySize, inventory, customItems]);

  const totalEstimate = useMemo(() => {
    const uk = CALCULATOR_OPTIONS.ukRegions.find(r => r.id === ukRegion);
    const spain = CALCULATOR_OPTIONS.spainRegions.find(r => r.id === spainRegion);

    if (!uk || !spain) return 0;

    let base = totalVolume * CALCULATOR_OPTIONS.pricePerM3;
    if (base < 500) base = 500;
    if (moveType === 'shared') base = base * 0.75; 

    base += uk.offset;
    base += spain.offset;

    if (extras.includes('packing')) base += totalVolume * 50;
    if (extras.includes('storage')) base += 180;
    if (extras.includes('insurance')) base += 120;

    return Math.round(base);
  }, [totalVolume, ukRegion, spainRegion, moveType, extras]);

  const toggleExtra = (id: string) => {
    setExtras(prev => prev.includes(id) ? prev.filter(e => e !== id) : [...prev, id]);
  };

  const handleSaveQuote = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;

    // Generate reference
    const ref = `ESP-${Math.floor(10000 + Math.random() * 90000)}`;
    setGeneratedRef(ref);

    // PRE-POPULATE CUSTOMS LIST FROM CALCULATOR SELECTIONS
    const initialCustomsList: any[] = [];

    // Add standard inventory
    INVENTORY_CATEGORIES.forEach(cat => {
      cat.items.forEach(item => {
        if (inventory[item.id] > 0) {
          initialCustomsList.push({
            id: `init-${item.id}`,
            description: `${inventory[item.id]} x ${item.label}`,
            value: '',
            boxNumber: ''
          });
        }
      });
    });

    // Add custom items
    customItems.forEach(item => {
      initialCustomsList.push({
        id: item.id,
        description: `${item.quantity} x ${item.label}`,
        value: '',
        boxNumber: ''
      });
    });

    // If no specific inventory was selected (property size mode), provide a placeholder
    if (initialCustomsList.length === 0 && calculationMode === 'size') {
      const sizeLabel = CALCULATOR_OPTIONS.propertySizes.find(s => s.id === propertySize)?.label;
      initialCustomsList.push({
        id: 'placeholder-1',
        description: `Full contents for ${sizeLabel}`,
        value: '',
        boxNumber: 'Multiple'
      });
    }

    const quoteData = {
      ref,
      email,
      volume: totalVolume,
      price: totalEstimate,
      date: moveDate,
      status: 'Quote Saved',
      origin: CALCULATOR_OPTIONS.ukRegions.find(r => r.id === ukRegion)?.label,
      destination: CALCULATOR_OPTIONS.spainRegions.find(r => r.id === spainRegion)?.label,
      moveType: moveType,
      extras: extras.map(exId => CALCULATOR_OPTIONS.services.find(s => s.id === exId)?.label || exId),
      propertySize: calculationMode === 'size' ? CALCULATOR_OPTIONS.propertySizes.find(s => s.id === propertySize)?.label : 'Custom Inventory',
      customsList: initialCustomsList,
      timestamp: Date.now()
    };

    const savedQuotes = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
    savedQuotes.push(quoteData);
    localStorage.setItem('britons_saved_quotes', JSON.stringify(savedQuotes));

    setSaveSuccess(true);
    setIsSaving(false);
  };

  const updateInventory = (id: string, delta: number) => {
    setInventory(prev => {
      const current = prev[id] || 0;
      const next = Math.max(0, current + delta);
      if (next === 0) {
        const { [id]: _, ...rest } = prev;
        return rest;
      }
      return { ...prev, [id]: next };
    });
  };

  const updateCustomItemQuantity = (id: string, delta: number) => {
    setCustomItems(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(0, item.quantity + delta) };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const addCustomItem = () => {
    if (!newCustomLabel || newCustomVolume === '' || newCustomVolume <= 0) return;
    const newItem: CustomItem = {
      id: `custom-${Date.now()}`,
      label: newCustomLabel,
      volume: Number(newCustomVolume),
      quantity: 1
    };
    setCustomItems(prev => [...prev, newItem]);
    setNewCustomLabel('');
    setNewCustomVolume('');
  };

  const clearInventory = () => {
    setInventory({});
    setCustomItems([]);
  };

  return (
    <section className="py-24 bg-slate-900 text-white overflow-hidden">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col lg:flex-row gap-16">
          <div className="lg:w-1/2 space-y-8">
            <div>
              <div className="inline-flex items-center space-x-2 bg-blue-500/10 text-blue-400 px-4 py-2 rounded-full text-sm font-bold mb-6">
                <Calculator size={16} />
                <span>Smart Volume Estimator</span>
              </div>
              <h2 className="text-4xl md:text-5xl font-bold mb-6">Quote Cost Calculator</h2>
              <p className="text-slate-400 text-lg leading-relaxed">
                Estimate your move based on property size or a detailed itemized inventory. Our system calculates volume precisely for Spanish transit in cubic meters.
              </p>
            </div>

            <div className="flex p-1 bg-slate-800 rounded-2xl w-fit">
              <button 
                onClick={() => setCalculationMode('size')}
                className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${calculationMode === 'size' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                Property Size
              </button>
              <button 
                onClick={() => setCalculationMode('inventory')}
                className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${calculationMode === 'inventory' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                Detailed Inventory
              </button>
            </div>

            <div className="space-y-8">
              {calculationMode === 'size' ? (
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Select Home Size</label>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {CALCULATOR_OPTIONS.propertySizes.map(size => (
                      <button
                        key={size.id}
                        onClick={() => setPropertySize(size.id)}
                        className={`p-4 rounded-xl border-2 text-left transition-all flex items-center justify-between ${propertySize === size.id ? 'bg-blue-500/10 border-blue-500 text-white' : 'border-slate-800 text-slate-400 hover:border-slate-700'}`}
                      >
                        <div className="flex items-center space-x-3">
                          <Home size={20} className={propertySize === size.id ? 'text-blue-400' : 'text-slate-500'} />
                          <span className="font-bold">{size.label}</span>
                        </div>
                        <span className="text-xs font-mono opacity-60">~{size.estVolume} m³</span>
                      </button>
                    ))}
                  </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Add Items</label>
                    <button onClick={clearInventory} className="text-xs font-bold text-red-400 hover:text-red-300 flex items-center space-x-1">
                      <Trash2 size={12} />
                      <span>Clear All</span>
                    </button>
                  </div>
                  <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                    {INVENTORY_CATEGORIES.map(category => (
                      <div key={category.id} className="bg-slate-800/50 rounded-2xl overflow-hidden border border-slate-800">
                        <button 
                          onClick={() => setActiveCategory(activeCategory === category.id ? null : category.id)}
                          className="w-full flex items-center justify-between p-4 hover:bg-slate-800 transition-colors"
                        >
                          <span className="font-bold">{category.label}</span>
                          {activeCategory === category.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                        </button>
                        {activeCategory === category.id && (
                          <div className="p-4 pt-0 space-y-4">
                            {category.items.map(item => (
                              <div key={item.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl">
                                <div className="flex flex-col">
                                  <span className="text-sm font-medium">{item.label}</span>
                                  <span className="text-[10px] text-slate-500 uppercase">{item.volume} m³</span>
                                </div>
                                <div className="flex items-center space-x-3">
                                  <button onClick={() => updateInventory(item.id, -1)} className="w-8 h-8 rounded-lg bg-slate-800 flex items-center justify-center hover:bg-slate-700 transition-colors">
                                    <Minus size={14} />
                                  </button>
                                  <span className="w-6 text-center font-bold text-blue-400">{inventory[item.id] || 0}</span>
                                  <button onClick={() => updateInventory(item.id, 1)} className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center hover:bg-blue-500 transition-colors">
                                    <Plus size={14} />
                                  </button>
                                </div>
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    ))}
                    <div className="bg-slate-800/50 rounded-2xl overflow-hidden border border-blue-500/30">
                        <button onClick={() => setActiveCategory(activeCategory === 'custom' ? null : 'custom')} className="w-full flex items-center justify-between p-4 hover:bg-slate-800 transition-colors">
                          <span className="font-bold flex items-center space-x-2">
                             <PlusCircle size={18} className="text-blue-400" />
                             <span>Custom & Unique Items</span>
                          </span>
                          {activeCategory === 'custom' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                        </button>
                        {activeCategory === 'custom' && (
                          <div className="p-4 pt-0 space-y-4">
                            <div className="grid grid-cols-2 gap-2 mb-4">
                              <input type="text" placeholder="Item name..." value={newCustomLabel} onChange={(e) => setNewCustomLabel(e.target.value)} className="bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none" />
                              <div className="flex space-x-2">
                                <input type="number" placeholder="Vol (m³)" value={newCustomVolume} onChange={(e) => setNewCustomVolume(e.target.value === '' ? '' : Number(e.target.value))} className="bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none w-full" />
                                <button onClick={addCustomItem} className="bg-blue-600 hover:bg-blue-500 px-3 py-2 rounded-lg text-white font-bold text-xs transition-colors">ADD</button>
                              </div>
                            </div>
                            {customItems.length > 0 && (
                              <div className="space-y-3 pt-2 border-t border-slate-700/50">
                                {customItems.map(item => (
                                  <div key={item.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-blue-500/10">
                                    <div className="flex flex-col">
                                      <span className="text-sm font-medium">{item.label}</span>
                                      <span className="text-[10px] text-slate-500 uppercase">{item.volume} m³ each</span>
                                    </div>
                                    <div className="flex items-center space-x-3">
                                      <button onClick={() => updateCustomItemQuantity(item.id, -1)} className="w-8 h-8 rounded-lg bg-slate-800 flex items-center justify-center hover:bg-slate-700 transition-colors"><Minus size={14} /></button>
                                      <span className="w-6 text-center font-bold text-blue-400">{item.quantity}</span>
                                      <button onClick={() => updateCustomItemQuantity(item.id, 1)} className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center hover:bg-blue-500 transition-colors"><Plus size={14} /></button>
                                    </div>
                                  </div>
                                ))}
                              </div>
                            )}
                          </div>
                        )}
                      </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setMoveType('dedicated')} className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center text-center space-y-2 ${moveType === 'dedicated' ? 'border-blue-500 bg-blue-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-700'}`}>
                  <Truck className={moveType === 'dedicated' ? 'text-blue-400' : 'text-slate-500'} />
                  <span className="font-bold block">Dedicated Load</span>
                  <span className="text-xs text-slate-500">Fastest Direct Route</span>
                </button>
                <button onClick={() => setMoveType('shared')} className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center text-center space-y-2 ${moveType === 'shared' ? 'border-blue-500 bg-blue-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-700'}`}>
                  <Package className={moveType === 'shared' ? 'text-blue-400' : 'text-slate-500'} />
                  <span className="font-bold block">Shared Load</span>
                  <span className="text-xs text-slate-500">Weekly Groupage</span>
                </button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">UK Origin</label>
                  <select value={ukRegion} onChange={(e) => setUkRegion(e.target.value)} className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none">
                    {CALCULATOR_OPTIONS.ukRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Spain Destination</label>
                  <select value={spainRegion} onChange={(e) => setSpainRegion(e.target.value)} className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none">
                    {CALCULATOR_OPTIONS.spainRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3 sm:col-span-2">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Desired Move Date</label>
                  <div className="relative group">
                    <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none group-focus-within:text-blue-400 transition-colors" size={18} />
                    <input 
                      type="date"
                      min={minMoveDate}
                      value={moveDate}
                      onChange={(e) => setMoveDate(e.target.value)}
                      className="w-full bg-slate-800 border border-slate-700 rounded-xl pl-12 pr-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-white [color-scheme:dark] transition-all"
                    />
                  </div>
                  <div className="flex items-start space-x-2 mt-2">
                    <AlertTriangle size={12} className="text-amber-500 mt-1 shrink-0" />
                    <p className="text-[11px] font-bold text-slate-500 uppercase tracking-wide leading-tight">
                      A minimum 14-day notice period is required to secure vehicle space and complete export customs processing for Spain.
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 w-full lg:sticky lg:top-32 h-fit">
            <div className="bg-white rounded-[2rem] p-8 md:p-12 text-slate-900 shadow-2xl relative border border-slate-100">
              <div className="absolute top-0 right-10 -translate-y-1/2 bg-blue-600 text-white px-6 py-2 rounded-full font-bold shadow-lg flex items-center space-x-2">
                <ShieldCheck size={18} />
                <span>Customs Included</span>
              </div>

              <div className="flex flex-col md:flex-row justify-between items-start mb-6 gap-6">
                <div>
                  <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mb-1">Total Volume</p>
                  <div className="flex items-baseline space-x-2">
                    <span className="text-4xl font-black text-slate-900">{totalVolume.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</span>
                    <span className="text-slate-400 font-bold">m³</span>
                  </div>
                </div>
                <div className="md:text-right">
                  <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mb-1">Estimated Cost</p>
                  <div className="flex items-baseline md:justify-end space-x-2">
                    <span className="text-5xl md:text-6xl font-black text-blue-600 tracking-tighter">£{totalEstimate.toLocaleString()}</span>
                  </div>
                  <p className="text-[10px] text-slate-400 font-bold mt-2 uppercase tracking-wide">
                    Minimum charge of £500 applies to all international moves.
                  </p>
                </div>
              </div>

              {saveSuccess ? (
                <div className="mb-8 p-6 bg-green-50 rounded-2xl border border-green-200 animate-fade-in text-center">
                  <CheckCircle size={32} className="text-green-600 mx-auto mb-3" />
                  <h4 className="font-bold text-slate-900 text-lg">Quote Saved Successfully!</h4>
                  <p className="text-slate-600 text-sm mt-1">Your reference: <span className="font-mono font-black text-blue-600">{generatedRef}</span></p>
                  <p className="text-xs text-slate-500 mt-2">A copy has been emailed to {email}. You can use this reference in the <span className="font-bold">Your Move</span> portal.</p>
                  <button 
                    onClick={() => setSaveSuccess(false)}
                    className="mt-4 text-xs font-bold text-blue-600 hover:underline"
                  >
                    Save to another email
                  </button>
                </div>
              ) : isSaving ? (
                <form onSubmit={handleSaveQuote} className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-200 animate-scale-up">
                  <h4 className="font-bold text-slate-900 mb-4 flex items-center space-x-2">
                    <Mail size={18} className="text-blue-600" />
                    <span>Send Quote to Email</span>
                  </h4>
                  <div className="space-y-4">
                    <input 
                      required
                      type="email" 
                      placeholder="Enter your email address..."
                      className="w-full bg-white border border-slate-300 rounded-xl px-4 py-3 text-slate-900 focus:ring-2 focus:ring-blue-500 outline-none"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                    />
                    <div className="flex gap-2">
                       <button 
                        type="submit"
                        className="flex-grow bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-md"
                      >
                        Confirm & Save
                      </button>
                      <button 
                        type="button"
                        onClick={() => setIsSaving(false)}
                        className="px-4 bg-white border border-slate-200 text-slate-500 rounded-xl hover:bg-slate-100"
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                </form>
              ) : (
                <div className="flex gap-3 mb-8">
                  <button 
                    onClick={() => setIsSaving(true)}
                    className="flex-grow bg-slate-100 hover:bg-blue-600 hover:text-white text-slate-700 font-bold py-4 rounded-2xl transition-all flex items-center justify-center space-x-2 group"
                  >
                    <Save size={18} className="group-hover:scale-110 transition-transform" />
                    <span>Save My Quote</span>
                  </button>
                </div>
              )}

              {moveDate && (
                <div className="mb-8 p-4 bg-blue-50 rounded-2xl flex items-center space-x-3 border border-blue-100">
                  <Calendar className="text-blue-600" size={20} />
                  <div>
                    <p className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Planned Departure</p>
                    <p className="text-slate-900 font-bold">{new Date(moveDate).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                  </div>
                </div>
              )}

              <div className="space-y-4 mb-10 border-t border-slate-100 pt-8">
                <p className="font-bold text-slate-900 flex items-center space-x-2">
                  <ListChecks size={18} className="text-blue-600" />
                  <span>Optional Protection & Services:</span>
                </p>
                <div className="grid grid-cols-1 gap-3">
                  {CALCULATOR_OPTIONS.services.map(service => (
                    <label key={service.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl cursor-pointer hover:bg-slate-100 transition-colors group">
                      <div className="flex items-center space-x-4">
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${extras.includes(service.id) ? 'bg-blue-600 border-blue-600' : 'border-slate-300'}`}>
                          {extras.includes(service.id) && <Plus size={12} className="text-white" />}
                        </div>
                        <span className="font-medium text-slate-700">{service.label}</span>
                      </div>
                      <input type="checkbox" className="hidden" checked={extras.includes(service.id)} onChange={() => toggleExtra(service.id)} />
                      <span className="text-slate-400 text-sm font-bold group-hover:text-blue-600">
                        {service.id === 'packing' ? `+£${Math.round(totalVolume * 50)}` : `+£${service.price}`}
                      </span>
                    </label>
                  ))}
                </div>
              </div>

              <button 
                onClick={onRequestFullQuote}
                className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold text-lg hover:bg-blue-600 transition-all transform hover:scale-[1.02] shadow-xl flex items-center justify-center space-x-3"
              >
                <span>Book Free Video Survey</span>
                <ArrowRight size={20} />
              </button>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255, 255, 255, 0.05); }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255, 255, 255, 0.2); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255, 255, 255, 0.3); }
      `}</style>
    </section>
  );
};

export default QuickQuoteCalculator;

import React, { useState, useEffect } from 'react';
import { 
  Lock, CheckCircle2, Truck, ClipboardList, MessageSquare, 
  Calendar, FileText, Send, Plus, Trash2, AlertCircle, 
  ChevronRight, MapPin, Package, ShieldCheck, UserCircle, History, ExternalLink,
  Upload, FileCheck, File, X, Loader2, Clock, Save
} from 'lucide-react';

interface CustomsItem {
  id: string;
  description: string;
  value: string;
  boxNumber?: string;
}

interface Message {
  id: string;
  text: string;
  sender: 'client' | 'agent';
  timestamp: string;
}

interface SavedQuote {
  ref: string;
  email: string;
  volume: number;
  price: number;
  date: string;
  status: string;
  origin: string;
  destination: string;
  customsList?: CustomsItem[];
}

interface UserDocument {
  id: string;
  name: string;
  status: 'required' | 'pending' | 'approved' | 'rejected';
  fileName?: string;
  uploadDate?: string;
}

const YourMove: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [reference, setReference] = useState('');
  const [surname, setSurname] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [activeMoveData, setActiveMoveData] = useState<SavedQuote | null>(null);
  const [activeTab, setActiveTab] = useState<'overview' | 'customs' | 'documents' | 'messages'>('overview');

  // Synced state for customs list
  const [itinerary, setItinerary] = useState<CustomsItem[]>([]);
  const [newItem, setNewItem] = useState({ description: '', value: '', boxNumber: '' });
  const [isSavingCustoms, setIsSavingCustoms] = useState(false);

  const [messages, setMessages] = useState<Message[]>([
    { id: '1', sender: 'agent', text: 'Hello! Welcome to your move portal. I am your coordinator, Mark. We have confirmed your loading for the 15th.', timestamp: '10:15 AM' },
    { id: '2', sender: 'client', text: 'Thank you Mark. Can I update the customs list until tomorrow?', timestamp: '11:20 AM' },
    { id: '3', sender: 'agent', text: 'Yes, of course. Please ensure all values are in GBP for the T1 document.', timestamp: '11:25 AM' },
  ]);
  const [newMessage, setNewMessage] = useState('');

  const [documents, setDocuments] = useState<UserDocument[]>([
    { id: 'doc-1', name: 'Lead Passenger Passport', status: 'required' },
    { id: 'doc-2', name: 'T1 Customs Declaration Form', status: 'required' },
    { id: 'doc-3', name: 'Spanish Residency Proof (TIE/NIE)', status: 'required' },
    { id: 'doc-4', name: 'Proof of UK Address (Council Tax/Utility)', status: 'required' },
  ]);
  const [isUploading, setIsUploading] = useState<string | null>(null);

  useEffect(() => {
    if (activeMoveData) {
      setItinerary(activeMoveData.customsList || []);
    }
  }, [activeMoveData]);

  const persistCustomsChanges = (updatedList: CustomsItem[]) => {
    if (!activeMoveData) return;
    const allQuotes = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
    const newQuotes = allQuotes.map((q: SavedQuote) => q.ref === activeMoveData.ref ? { ...q, customsList: updatedList } : q);
    localStorage.setItem('britons_saved_quotes', JSON.stringify(newQuotes));
    setActiveMoveData({ ...activeMoveData, customsList: updatedList });

    // Visual feedback for save
    setIsSavingCustoms(true);
    setTimeout(() => setIsSavingCustoms(false), 1000);
  };

  const updateItemInline = (id: string, field: keyof CustomsItem, value: string) => {
    const updated = itinerary.map(item => item.id === id ? { ...item, [field]: value } : item);
    setItinerary(updated);
    persistCustomsChanges(updated);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    setTimeout(() => {
      const savedQuotes: SavedQuote[] = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
      const foundQuote = savedQuotes.find(q => q.ref.toUpperCase() === reference.toUpperCase());

      if (reference.toUpperCase() === 'ESP-12345' || foundQuote) {
        if (foundQuote) {
          setActiveMoveData(foundQuote);
        } else {
          // Mock move if using the demo reference
          setActiveMoveData({
            ref: 'ESP-12345',
            email: 'demo@example.com',
            volume: 15,
            price: 3400,
            date: '2024-05-15',
            status: 'In Preparation',
            origin: 'London, UK',
            destination: 'Madrid, Spain',
            customsList: [
              { id: '1', description: 'Kitchenware (Standard Boxes)', value: '£400', boxNumber: '1-4' },
              { id: '2', description: 'Dining Room Table (Wrapped)', value: '£800', boxNumber: '7' },
            ]
          });
        }
        setIsAuthenticated(true);
      } else {
        setError('Reference not found. Please check your quote email.');
      }
      setLoading(false);
    }, 1200);
  };

  const handleAddItem = () => {
    if (newItem.description && newItem.value) {
      const updatedList = [...itinerary, { ...newItem, id: Date.now().toString() }];
      setItinerary(updatedList);
      persistCustomsChanges(updatedList);
      setNewItem({ description: '', value: '', boxNumber: '' });
    }
  };

  const removeItem = (id: string) => {
    const updatedList = itinerary.filter(i => i.id !== id);
    setItinerary(updatedList);
    persistCustomsChanges(updatedList);
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (newMessage.trim()) {
      const msg: Message = {
        id: Date.now().toString(),
        sender: 'client',
        text: newMessage,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };
      setMessages([...messages, msg]);
      setNewMessage('');
    }
  };

  const handleFileUpload = (docId: string, event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsUploading(docId);
    setTimeout(() => {
      setDocuments(prev => prev.map(doc => {
        if (doc.id === docId) {
          return { ...doc, status: 'pending', fileName: file.name, uploadDate: new Date().toLocaleDateString() };
        }
        return doc;
      }));
      setIsUploading(null);
    }, 1500);
  };

  const removeFile = (docId: string) => {
    setDocuments(prev => prev.map(doc => {
      if (doc.id === docId) return { ...doc, status: 'required', fileName: undefined, uploadDate: undefined };
      return doc;
    }));
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center bg-slate-50 px-4 py-12">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 border border-slate-100">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4"><Lock size={32} /></div>
            <h2 className="text-3xl font-bold text-slate-900">Your Move Portal</h2>
            <p className="text-slate-500 mt-2 text-sm">Enter your quote reference or move ID</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Move Reference</label>
              <input required type="text" placeholder="e.g. ESP-12345" className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all ${error ? 'border-red-500' : 'border-slate-200'}`} value={reference} onChange={(e) => setReference(e.target.value)} />
              {error && <p className="text-red-500 text-[10px] font-bold mt-1 uppercase tracking-wider">{error}</p>}
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Lead Surname / Email</label>
              <input required type="text" placeholder="Enter your registered name" className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" value={surname} onChange={(e) => setSurname(e.target.value)} />
            </div>
            <button type="submit" disabled={loading} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2">
              {loading ? <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <><span className="text-white">Access Dashboard</span><ChevronRight size={18} className="text-white"/></>}
            </button>
          </form>
          <div className="mt-8 p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200"><p className="text-[10px] text-slate-400 font-bold uppercase text-center mb-2">Helpful Tip</p><p className="text-[10px] text-slate-600 leading-relaxed text-center">Don't have a reference? Use the <span className="text-blue-600 font-bold">Quick Quote Calculator</span> and click 'Save Quote' to generate a reference instantly.</p></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <div className="bg-slate-900 text-white pt-12 pb-24">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center space-x-3 text-blue-400 text-sm font-bold uppercase tracking-widest mb-2"><Truck size={16} /><span>Reference: {reference || activeMoveData?.ref}</span></div>
              <h2 className="text-4xl font-black">Hello, {surname || 'Valued Customer'}</h2>
              <p className="text-slate-400 mt-2">Your relocation to <span className="text-white font-bold">{activeMoveData?.destination || 'Spain'}</span> is {activeMoveData?.status.toLowerCase() === 'quote saved' ? 'ready for booking.' : 'currently in progress.'}</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="bg-white/10 p-4 rounded-2xl border border-white/10 backdrop-blur-md">
                 <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-1">Target Date</p><p className="text-xl font-black">{activeMoveData?.date ? new Date(activeMoveData.date).toLocaleDateString() : 'TBC'}</p>
              </div>
              <div className="bg-blue-600 p-4 rounded-2xl border border-blue-500 shadow-xl">
                 <p className="text-xs text-blue-100 font-bold uppercase tracking-widest mb-1">Status</p><p className="text-xl font-black">{activeMoveData?.status || 'Active'}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-12">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden min-h-[600px] flex flex-col md:flex-row">
          <div className="w-full md:w-64 bg-slate-50 border-r border-slate-100 p-6 space-y-2">
            <button onClick={() => setActiveTab('overview')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><Package size={20} /><span>Overview</span></button>
            <button onClick={() => setActiveTab('customs')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'customs' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><ClipboardList size={20} /><span>Customs List</span></button>
            <button onClick={() => setActiveTab('documents')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'documents' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><FileCheck size={20} /><span>Documents</span></button>
            <button onClick={() => setActiveTab('messages')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'messages' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><MessageSquare size={20} /><span>Messages</span></button>
            <div className="pt-8 mt-8 border-t border-slate-200"><p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-4 px-4">Contact Agent</p><div className="px-4 py-3 bg-white rounded-xl border border-slate-100 shadow-sm flex items-center space-x-3"><div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600"><UserCircle size={20} /></div><div><p className="text-sm font-bold text-slate-800">Mark Collins</p><p className="text-[10px] text-slate-500">Coordinator</p></div></div></div>
            <button onClick={() => setIsAuthenticated(false)} className="w-full mt-12 text-xs font-bold text-slate-400 hover:text-red-500 text-left px-4">Log Out of Portal</button>
          </div>

          <div className="flex-grow p-6 md:p-10">
            {activeTab === 'overview' && (
              <div className="space-y-8 animate-fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-6">
                    <h3 className="text-2xl font-bold text-slate-900">Your Move Progress</h3>
                    <div className="space-y-4">
                      <div className="flex items-center space-x-4 p-4 bg-green-50 rounded-2xl border border-green-100"><div className="bg-green-500 text-white p-2 rounded-lg"><CheckCircle2 size={20} /></div><div><p className="font-bold text-slate-900">Quote Received</p><p className="text-xs text-slate-500">Completed via Web Calculator</p></div></div>
                      <div className={`flex items-center space-x-4 p-4 rounded-2xl border transition-all ${itinerary.length > 0 ? 'bg-green-50 border-green-100' : 'bg-blue-50 border-blue-100'}`}><div className={`${itinerary.length > 0 ? 'bg-green-500' : 'bg-blue-600'} text-white p-2 rounded-lg`}><ClipboardList size={20} /></div><div><p className="font-bold text-slate-900">Customs Declaration</p><p className="text-xs text-slate-500">{itinerary.length > 0 ? `${itinerary.length} items declared` : 'Please start your inventory list'}</p></div></div>
                    </div>
                  </div>
                  <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100">
                    <h3 className="text-xl font-bold text-slate-900 mb-6 flex items-center space-x-2"><MapPin size={18} className="text-blue-600" /><span>Key Details</span></h3>
                    <div className="space-y-4">
                      <div className="flex justify-between border-b border-slate-200 pb-2"><span className="text-slate-500 text-sm">Origin</span><span className="font-bold text-slate-900">{activeMoveData?.origin}</span></div>
                      <div className="flex justify-between border-b border-slate-200 pb-2"><span className="text-slate-500 text-sm">Destination</span><span className="font-bold text-slate-900">{activeMoveData?.destination}</span></div>
                      <div className="flex justify-between border-b border-slate-200 pb-2"><span className="text-slate-500 text-sm">Volume</span><span className="font-bold text-slate-900">{activeMoveData?.volume} m³</span></div>
                      <div className="flex justify-between"><span className="text-slate-500 text-sm">Estimated Total</span><span className="font-bold text-blue-600 text-lg">£{activeMoveData?.price.toLocaleString()}</span></div>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'customs' && (
              <div className="space-y-8 animate-fade-in">
                <div className="flex justify-between items-center">
                  <div>
                    <h3 className="text-2xl font-bold text-slate-900">Customs Itinerary (T1 Document)</h3>
                    <p className="text-xs text-slate-500 mt-1 font-bold flex items-center gap-2">
                       {itinerary.length > 0 && itinerary.every(i => i.value !== '') ? (
                          <span className="text-green-600 flex items-center gap-1 uppercase tracking-widest"><CheckCircle2 size={12}/> Manifest Complete</span>
                       ) : (
                          <span className="text-amber-600 flex items-center gap-1 uppercase tracking-widest"><AlertCircle size={12}/> Please refine values for pre-filled items</span>
                       )}
                       {isSavingCustoms && <><Loader2 size={12} className="animate-spin text-blue-600"/> <span className="text-blue-600 uppercase tracking-widest">Changes Saved</span></>}
                    </p>
                  </div>
                  <button className="bg-slate-900 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center space-x-2 shadow-lg"><FileText size={16} /><span>Preview T1 Form</span></button>
                </div>

                <div className="overflow-x-auto rounded-2xl border border-slate-200 shadow-sm bg-white">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 text-slate-500 text-[10px] uppercase tracking-widest font-black">
                      <tr>
                        <th className="px-6 py-4">Item Description</th>
                        <th className="px-6 py-4">Est. Value (GBP)</th>
                        <th className="px-6 py-4 w-32">Box No.</th>
                        <th className="px-6 py-4 text-center">Action</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {itinerary.length === 0 && (
                        <tr><td colSpan={4} className="px-6 py-12 text-center text-slate-400 italic">No items found. Add items manually below.</td></tr>
                      )}
                      {itinerary.map(item => (
                        <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
                          <td className="px-6 py-4">
                            <input 
                              type="text" 
                              value={item.description} 
                              onChange={(e) => updateItemInline(item.id, 'description', e.target.value)}
                              className="w-full bg-transparent border-none text-sm font-bold text-slate-900 focus:ring-0 p-0"
                            />
                          </td>
                          <td className="px-6 py-4">
                            <div className="flex items-center space-x-1">
                               <span className="text-slate-400 font-bold">£</span>
                               <input 
                                  type="text" 
                                  placeholder="0.00" 
                                  value={item.value} 
                                  onChange={(e) => updateItemInline(item.id, 'value', e.target.value)}
                                  className={`w-24 bg-transparent border-b ${item.value === '' ? 'border-amber-200 bg-amber-50/30' : 'border-transparent'} text-sm font-bold text-slate-900 focus:ring-0 p-0.5 focus:border-blue-500`}
                               />
                            </div>
                          </td>
                          <td className="px-6 py-4">
                            <input 
                              type="text" 
                              placeholder="e.g. 1" 
                              value={item.boxNumber} 
                              onChange={(e) => updateItemInline(item.id, 'boxNumber', e.target.value)}
                              className="w-full bg-transparent border-none text-sm font-mono text-slate-600 focus:ring-0 p-0"
                            />
                          </td>
                          <td className="px-6 py-4 text-center">
                            <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 transition-colors p-2 opacity-0 group-hover:opacity-100">
                              <Trash2 size={16} />
                            </button>
                          </td>
                        </tr>
                      ))}
                      <tr className="bg-blue-50/20">
                        <td className="px-6 py-4">
                          <input type="text" placeholder="Add additional item..." className="bg-transparent border-none outline-none w-full text-sm font-bold placeholder:text-blue-300" value={newItem.description} onChange={(e) => setNewItem({...newItem, description: e.target.value})} />
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center space-x-1">
                             <span className="text-blue-300 font-bold">£</span>
                             <input type="text" placeholder="Value" className="bg-transparent border-none outline-none w-full text-sm font-bold placeholder:text-blue-300" value={newItem.value} onChange={(e) => setNewItem({...newItem, value: e.target.value})} />
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <input type="text" placeholder="Box #" className="bg-transparent border-none outline-none w-full text-sm font-mono placeholder:text-blue-300" value={newItem.boxNumber} onChange={(e) => setNewItem({...newItem, boxNumber: e.target.value})} />
                        </td>
                        <td className="px-6 py-4 text-center">
                          <button onClick={handleAddItem} className="bg-blue-600 text-white p-2.5 rounded-xl shadow-lg hover:bg-blue-700 transition-all">
                             <Plus size={18} />
                          </button>
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </div>
                {itinerary.length > 0 && <div className="p-4 bg-green-50 border border-green-100 rounded-xl flex items-center space-x-3"><CheckCircle2 className="text-green-600" size={18} /><p className="text-xs font-bold text-green-800 uppercase tracking-wide">Sync Active: Your logistics agent can now review these items in real-time.</p></div>}
              </div>
            )}

            {activeTab === 'documents' && (
              <div className="space-y-8 animate-fade-in">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4"><div><h3 className="text-2xl font-bold text-slate-900">Required Documentation</h3><p className="text-slate-500 text-sm mt-1">Upload files required for customs clearance.</p></div><div className="bg-slate-100 px-4 py-2 rounded-xl border border-slate-200"><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1 text-center">Status</p><div className="flex items-center space-x-2"><span className="text-xs font-bold text-slate-700">{documents.filter(d => d.status === 'pending' || d.status === 'approved').length} / {documents.length} Uploaded</span></div></div></div>
                <div className="grid grid-cols-1 gap-4">
                  {documents.map(doc => (
                    <div key={doc.id} className={`p-6 rounded-3xl border transition-all flex flex-col md:flex-row items-center justify-between gap-6 ${doc.status === 'required' ? 'bg-white border-slate-200' : doc.status === 'pending' ? 'bg-blue-50 border-blue-200' : 'bg-green-50 border-green-200'}`}>
                      <div className="flex items-center space-x-4"><div className={`p-3 rounded-2xl ${doc.status === 'required' ? 'bg-slate-100 text-slate-400' : 'bg-blue-100 text-blue-600'}`}><File size={24} /></div><div><h4 className="font-bold text-slate-900">{doc.name}</h4>{doc.fileName ? <p className="text-xs text-slate-500 font-medium">Uploaded: {doc.fileName}</p> : <p className="text-xs text-slate-400 uppercase font-black tracking-widest mt-1">File Required</p>}</div></div>
                      <div className="flex items-center space-x-3 w-full md:w-auto">
                        {doc.status === 'required' ? <label className="flex-grow md:flex-grow-0 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-bold text-sm cursor-pointer transition-all flex items-center justify-center space-x-2 shadow-lg">{isUploading === doc.id ? <Loader2 size={18} className="animate-spin" /> : <Upload size={18} />}<span>{isUploading === doc.id ? 'Uploading...' : 'Upload File'}</span><input type="file" className="hidden" onChange={(e) => handleFileUpload(doc.id, e)} accept=".pdf,.jpg,.jpeg,.png" disabled={isUploading !== null} /></label> : <div className="flex items-center space-x-2"><div className={`flex items-center space-x-1.5 px-3 py-1.5 rounded-lg text-xs font-bold uppercase ${doc.status === 'pending' ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'}`}>{doc.status === 'pending' ? <Clock size={14} /> : <CheckCircle2 size={14} />}<span>{doc.status}</span></div><button onClick={() => removeFile(doc.id)} className="p-2.5 text-slate-400 hover:text-red-500 bg-white border border-slate-200 rounded-xl transition-colors"><Trash2 size={16} /></button></div>}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'messages' && (
              <div className="flex flex-col h-full max-h-[600px] animate-fade-in">
                <div className="flex items-center justify-between mb-6 pb-4 border-b border-slate-100"><h3 className="text-2xl font-bold text-slate-900">Coordinator Chat</h3><div className="flex items-center space-x-2"><div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div><span className="text-xs text-slate-500 font-bold uppercase tracking-widest">Mark is online</span></div></div>
                <div className="flex-grow overflow-y-auto pr-4 space-y-4 custom-scrollbar mb-6 min-h-[300px]">{messages.map(msg => (<div key={msg.id} className={`flex flex-col ${msg.sender === 'client' ? 'items-end' : 'items-start'}`}><div className={`max-w-[80%] px-4 py-3 rounded-2xl text-sm ${msg.sender === 'client' ? 'bg-blue-600 text-white rounded-br-none' : 'bg-slate-100 text-slate-800 rounded-bl-none'}`}>{msg.text}</div><span className="text-[10px] text-slate-400 mt-1 font-bold">{msg.timestamp}</span></div>))}</div>
                <form onSubmit={handleSendMessage} className="flex items-center space-x-3 bg-slate-50 p-2 rounded-2xl border border-slate-200"><input type="text" placeholder="Type your message..." className="flex-grow bg-transparent px-4 py-2 outline-none text-slate-800" value={newMessage} onChange={(e) => setNewMessage(e.target.value)} /><button type="submit" className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-colors shadow-lg"><Send size={18} /></button></form>
              </div>
            )}
          </div>
        </div>
      </div>
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 4px; } .custom-scrollbar::-webkit-scrollbar-track { background: transparent; } .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }`}</style>
    </div>
  );
};

export default YourMove;

import React, { useState, useMemo } from 'react';
import { Calculator, Home, Info, ShieldCheck, Truck, Package, Plus, Minus, ChevronDown, ChevronUp, Trash2, ArrowRight, ListChecks, Calendar, PlusCircle, AlertTriangle, Mail, Save, CheckCircle } from 'lucide-react';
import { CALCULATOR_OPTIONS, INVENTORY_CATEGORIES } from '../constants';

interface QuickQuoteCalculatorProps {
  onRequestFullQuote: () => void;
}

interface CustomItem {
  id: string;
  label: string;
  volume: number;
  quantity: number;
}

const QuickQuoteCalculator: React.FC<QuickQuoteCalculatorProps> = ({ onRequestFullQuote }) => {
  const [calculationMode, setCalculationMode] = useState<'size' | 'inventory'>('size');
  const [propertySize, setPropertySize] = useState(CALCULATOR_OPTIONS.propertySizes[1].id);
  const [ukRegion, setUkRegion] = useState(CALCULATOR_OPTIONS.ukRegions[0].id);
  const [spainRegion, setSpainRegion] = useState(CALCULATOR_OPTIONS.spainRegions[0].id);
  const [moveType, setMoveType] = useState<'dedicated' | 'shared'>('dedicated');
  const [moveDate, setMoveDate] = useState('');
  const [extras, setExtras] = useState<string[]>([]);
  const [inventory, setInventory] = useState<Record<string, number>>({});
  const [customItems, setCustomItems] = useState<CustomItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<string | null>(INVENTORY_CATEGORIES[0].id);

  // Save Quote State
  const [isSaving, setIsSaving] = useState(false);
  const [email, setEmail] = useState('');
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [generatedRef, setGeneratedRef] = useState('');

  // Custom item input state
  const [newCustomLabel, setNewCustomLabel] = useState('');
  const [newCustomVolume, setNewCustomVolume] = useState<number | ''>('');

  // Calculate minimum move date
  const minMoveDate = useMemo(() => {
    const date = new Date();
    date.setDate(date.getDate() + 14);
    return date.toISOString().split('T')[0];
  }, []);

  const totalVolume = useMemo(() => {
    if (calculationMode === 'size') {
      const size = CALCULATOR_OPTIONS.propertySizes.find(s => s.id === propertySize);
      return size?.estVolume || 0;
    } else {
      let volume = 0;
      INVENTORY_CATEGORIES.forEach(cat => {
        cat.items.forEach(item => {
          if (inventory[item.id]) {
            volume += inventory[item.id] * item.volume;
          }
        });
      });
      customItems.forEach(item => {
        volume += item.quantity * item.volume;
      });
      return parseFloat(volume.toFixed(2));
    }
  }, [calculationMode, propertySize, inventory, customItems]);

  const totalEstimate = useMemo(() => {
    const uk = CALCULATOR_OPTIONS.ukRegions.find(r => r.id === ukRegion);
    const spain = CALCULATOR_OPTIONS.spainRegions.find(r => r.id === spainRegion);

    if (!uk || !spain) return 0;

    let base = totalVolume * CALCULATOR_OPTIONS.pricePerM3;
    if (base < 500) base = 500;
    if (moveType === 'shared') base = base * 0.75; 

    base += uk.offset;
    base += spain.offset;

    if (extras.includes('packing')) base += totalVolume * 50;
    if (extras.includes('storage')) base += 180;
    if (extras.includes('insurance')) base += 120;

    return Math.round(base);
  }, [totalVolume, ukRegion, spainRegion, moveType, extras]);

  const toggleExtra = (id: string) => {
    setExtras(prev => prev.includes(id) ? prev.filter(e => e !== id) : [...prev, id]);
  };

  const handleSaveQuote = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;

    // Generate reference
    const ref = `ESP-${Math.floor(10000 + Math.random() * 90000)}`;
    setGeneratedRef(ref);

    // PRE-POPULATE CUSTOMS LIST FROM CALCULATOR SELECTIONS
    const initialCustomsList: any[] = [];

    // Add standard inventory if in inventory mode
    if (calculationMode === 'inventory') {
      INVENTORY_CATEGORIES.forEach(cat => {
        cat.items.forEach(item => {
          if (inventory[item.id] > 0) {
            initialCustomsList.push({
              id: `init-${item.id}`,
              description: `${inventory[item.id]} x ${item.label}`,
              value: '',
              boxNumber: ''
            });
          }
        });
      });

      // Add custom items
      customItems.forEach(item => {
        initialCustomsList.push({
          id: item.id,
          description: `${item.quantity} x ${item.label}`,
          value: '',
          boxNumber: ''
        });
      });
    }

    // Removed the "Full contents for..." placeholder as requested by the user. 
    // If calculationMode is 'size', initialCustomsList remains empty.

    const quoteData = {
      ref,
      email,
      volume: totalVolume,
      price: totalEstimate,
      date: moveDate,
      status: 'Quote Saved',
      origin: CALCULATOR_OPTIONS.ukRegions.find(r => r.id === ukRegion)?.label,
      destination: CALCULATOR_OPTIONS.spainRegions.find(r => r.id === spainRegion)?.label,
      moveType: moveType,
      extras: extras.map(exId => CALCULATOR_OPTIONS.services.find(s => s.id === exId)?.label || exId),
      propertySize: calculationMode === 'size' ? CALCULATOR_OPTIONS.propertySizes.find(s => s.id === propertySize)?.label : 'Custom Inventory',
      customsList: initialCustomsList,
      timestamp: Date.now()
    };

    const savedQuotes = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
    savedQuotes.push(quoteData);
    localStorage.setItem('britons_saved_quotes', JSON.stringify(savedQuotes));

    setSaveSuccess(true);
    setIsSaving(false);
  };

  const updateInventory = (id: string, delta: number) => {
    setInventory(prev => {
      const current = prev[id] || 0;
      const next = Math.max(0, current + delta);
      if (next === 0) {
        const { [id]: _, ...rest } = prev;
        return rest;
      }
      return { ...prev, [id]: next };
    });
  };

  const updateCustomItemQuantity = (id: string, delta: number) => {
    setCustomItems(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, quantity: Math.max(0, item.quantity + delta) };
      }
      return item;
    }).filter(item => item.quantity > 0));
  };

  const addCustomItem = () => {
    if (!newCustomLabel || newCustomVolume === '' || newCustomVolume <= 0) return;
    const newItem: CustomItem = {
      id: `custom-${Date.now()}`,
      label: newCustomLabel,
      volume: Number(newCustomVolume),
      quantity: 1
    };
    setCustomItems(prev => [...prev, newItem]);
    setNewCustomLabel('');
    setNewCustomVolume('');
  };

  const clearInventory = () => {
    setInventory({});
    setCustomItems([]);
  };

  return (
    <section className="py-24 bg-slate-900 text-white overflow-hidden">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col lg:flex-row gap-16">
          <div className="lg:w-1/2 space-y-8">
            <div>
              <div className="inline-flex items-center space-x-2 bg-blue-500/10 text-blue-400 px-4 py-2 rounded-full text-sm font-bold mb-6">
                <Calculator size={16} />
                <span>Smart Volume Estimator</span>
              </div>
              <h2 className="text-4xl md:text-5xl font-bold mb-6">Quote Cost Calculator</h2>
              <p className="text-slate-400 text-lg leading-relaxed">
                Estimate your move based on property size or a detailed itemized inventory. Our system calculates volume precisely for Spanish transit in cubic meters.
              </p>
            </div>

            <div className="flex p-1 bg-slate-800 rounded-2xl w-fit">
              <button 
                onClick={() => setCalculationMode('size')}
                className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${calculationMode === 'size' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                Property Size
              </button>
              <button 
                onClick={() => setCalculationMode('inventory')}
                className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${calculationMode === 'inventory' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                Detailed Inventory
              </button>
            </div>

            <div className="space-y-8">
              {calculationMode === 'size' ? (
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Select Home Size</label>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {CALCULATOR_OPTIONS.propertySizes.map(size => (
                      <button
                        key={size.id}
                        onClick={() => setPropertySize(size.id)}
                        className={`p-4 rounded-xl border-2 text-left transition-all flex items-center justify-between ${propertySize === size.id ? 'bg-blue-500/10 border-blue-500 text-white' : 'border-slate-800 text-slate-400 hover:border-slate-700'}`}
                      >
                        <div className="flex items-center space-x-3">
                          <Home size={20} className={propertySize === size.id ? 'text-blue-400' : 'text-slate-500'} />
                          <span className="font-bold">{size.label}</span>
                        </div>
                        <span className="text-xs font-mono opacity-60">~{size.estVolume} m³</span>
                      </button>
                    ))}
                  </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="flex items-center justify-between">
                    <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Add Items</label>
                    <button onClick={clearInventory} className="text-xs font-bold text-red-400 hover:text-red-300 flex items-center space-x-1">
                      <Trash2 size={12} />
                      <span>Clear All</span>
                    </button>
                  </div>
                  <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                    {INVENTORY_CATEGORIES.map(category => (
                      <div key={category.id} className="bg-slate-800/50 rounded-2xl overflow-hidden border border-slate-800">
                        <button 
                          onClick={() => setActiveCategory(activeCategory === category.id ? null : category.id)}
                          className="w-full flex items-center justify-between p-4 hover:bg-slate-800 transition-colors"
                        >
                          <span className="font-bold">{category.label}</span>
                          {activeCategory === category.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                        </button>
                        {activeCategory === category.id && (
                          <div className="p-4 pt-0 space-y-4">
                            {category.items.map(item => (
                              <div key={item.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl">
                                <div className="flex flex-col">
                                  <span className="text-sm font-medium">{item.label}</span>
                                  <span className="text-[10px] text-slate-500 uppercase">{item.volume} m³</span>
                                </div>
                                <div className="flex items-center space-x-3">
                                  <button onClick={() => updateInventory(item.id, -1)} className="w-8 h-8 rounded-lg bg-slate-800 flex items-center justify-center hover:bg-slate-700 transition-colors">
                                    <Minus size={14} />
                                  </button>
                                  <span className="w-6 text-center font-bold text-blue-400">{inventory[item.id] || 0}</span>
                                  <button onClick={() => updateInventory(item.id, 1)} className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center hover:bg-blue-500 transition-colors">
                                    <Plus size={14} />
                                  </button>
                                </div>
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    ))}
                    <div className="bg-slate-800/50 rounded-2xl overflow-hidden border border-blue-500/30">
                        <button onClick={() => setActiveCategory(activeCategory === 'custom' ? null : 'custom')} className="w-full flex items-center justify-between p-4 hover:bg-slate-800 transition-colors">
                          <span className="font-bold flex items-center space-x-2">
                             <PlusCircle size={18} className="text-blue-400" />
                             <span>Custom & Unique Items</span>
                          </span>
                          {activeCategory === 'custom' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                        </button>
                        {activeCategory === 'custom' && (
                          <div className="p-4 pt-0 space-y-4">
                            <div className="grid grid-cols-2 gap-2 mb-4">
                              <input type="text" placeholder="Item name..." value={newCustomLabel} onChange={(e) => setNewCustomLabel(e.target.value)} className="bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none" />
                              <div className="flex space-x-2">
                                <input type="number" placeholder="Vol (m³)" value={newCustomVolume} onChange={(e) => setNewCustomVolume(e.target.value === '' ? '' : Number(e.target.value))} className="bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none w-full" />
                                <button onClick={addCustomItem} className="bg-blue-600 hover:bg-blue-500 px-3 py-2 rounded-lg text-white font-bold text-xs transition-colors">ADD</button>
                              </div>
                            </div>
                            {customItems.length > 0 && (
                              <div className="space-y-3 pt-2 border-t border-slate-700/50">
                                {customItems.map(item => (
                                  <div key={item.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-blue-500/10">
                                    <div className="flex flex-col">
                                      <span className="text-sm font-medium">{item.label}</span>
                                      <span className="text-[10px] text-slate-500 uppercase">{item.volume} m³ each</span>
                                    </div>
                                    <div className="flex items-center space-x-3">
                                      <button onClick={() => updateCustomItemQuantity(item.id, -1)} className="w-8 h-8 rounded-lg bg-slate-800 flex items-center justify-center hover:bg-slate-700 transition-colors"><Minus size={14} /></button>
                                      <span className="w-6 text-center font-bold text-blue-400">{item.quantity}</span>
                                      <button onClick={() => updateCustomItemQuantity(item.id, 1)} className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center hover:bg-blue-500 transition-colors"><Plus size={14} /></button>
                                    </div>
                                  </div>
                                ))}
                              </div>
                            )}
                          </div>
                        )}
                      </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setMoveType('dedicated')} className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center text-center space-y-2 ${moveType === 'dedicated' ? 'border-blue-500 bg-blue-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-700'}`}>
                  <Truck className={moveType === 'dedicated' ? 'text-blue-400' : 'text-slate-500'} />
                  <span className="font-bold block">Dedicated Load</span>
                  <span className="text-xs text-slate-500">Fastest Direct Route</span>
                </button>
                <button onClick={() => setMoveType('shared')} className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center text-center space-y-2 ${moveType === 'shared' ? 'border-blue-500 bg-blue-500/10' : 'border-slate-800 bg-slate-800/50 hover:border-slate-700'}`}>
                  <Package className={moveType === 'shared' ? 'text-blue-400' : 'text-slate-500'} />
                  <span className="font-bold block">Shared Load</span>
                  <span className="text-xs text-slate-500">Weekly Groupage</span>
                </button>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">UK Origin</label>
                  <select value={ukRegion} onChange={(e) => setUkRegion(e.target.value)} className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none">
                    {CALCULATOR_OPTIONS.ukRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Spain Destination</label>
                  <select value={spainRegion} onChange={(e) => setSpainRegion(e.target.value)} className="w-full bg-slate-800 border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none">
                    {CALCULATOR_OPTIONS.spainRegions.map(r => <option key={r.id} value={r.id}>{r.label}</option>)}
                  </select>
                </div>
                <div className="space-y-3 sm:col-span-2">
                  <label className="text-sm font-bold text-slate-400 uppercase tracking-widest">Desired Move Date</label>
                  <div className="relative group">
                    <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none group-focus-within:text-blue-400 transition-colors" size={18} />
                    <input 
                      type="date"
                      min={minMoveDate}
                      value={moveDate}
                      onChange={(e) => setMoveDate(e.target.value)}
                      className="w-full bg-slate-800 border border-slate-700 rounded-xl pl-12 pr-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-white [color-scheme:dark] transition-all"
                    />
                  </div>
                  <div className="flex items-start space-x-2 mt-2">
                    <AlertTriangle size={12} className="text-amber-500 mt-1 shrink-0" />
                    <p className="text-[11px] font-bold text-slate-500 uppercase tracking-wide leading-tight">
                      A minimum 14-day notice period is required to secure vehicle space and complete export customs processing for Spain.
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:w-1/2 w-full lg:sticky lg:top-32 h-fit">
            <div className="bg-white rounded-[2rem] p-8 md:p-12 text-slate-900 shadow-2xl relative border border-slate-100">
              <div className="absolute top-0 right-10 -translate-y-1/2 bg-blue-600 text-white px-6 py-2 rounded-full font-bold shadow-lg flex items-center space-x-2">
                <ShieldCheck size={18} />
                <span>Customs Included</span>
              </div>

              <div className="flex flex-col md:flex-row justify-between items-start mb-6 gap-6">
                <div>
                  <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mb-1">Total Volume</p>
                  <div className="flex items-baseline space-x-2">
                    <span className="text-4xl font-black text-slate-900">{totalVolume.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })}</span>
                    <span className="text-slate-400 font-bold">m³</span>
                  </div>
                </div>
                <div className="md:text-right">
                  <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mb-1">Estimated Cost</p>
                  <div className="flex items-baseline md:justify-end space-x-2">
                    <span className="text-5xl md:text-6xl font-black text-blue-600 tracking-tighter">£{totalEstimate.toLocaleString()}</span>
                  </div>
                  <p className="text-[10px] text-slate-400 font-bold mt-2 uppercase tracking-wide">
                    Minimum charge of £500 applies to all international moves.
                  </p>
                </div>
              </div>

              {saveSuccess ? (
                <div className="mb-8 p-6 bg-green-50 rounded-2xl border border-green-200 animate-fade-in text-center">
                  <CheckCircle size={32} className="text-green-600 mx-auto mb-3" />
                  <h4 className="font-bold text-slate-900 text-lg">Quote Saved Successfully!</h4>
                  <p className="text-slate-600 text-sm mt-1">Your reference: <span className="font-mono font-black text-blue-600">{generatedRef}</span></p>
                  <p className="text-xs text-slate-500 mt-2">A copy has been emailed to {email}. You can use this reference in the <span className="font-bold">Your Move</span> portal.</p>
                  <button 
                    onClick={() => setSaveSuccess(false)}
                    className="mt-4 text-xs font-bold text-blue-600 hover:underline"
                  >
                    Save to another email
                  </button>
                </div>
              ) : isSaving ? (
                <form onSubmit={handleSaveQuote} className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-200 animate-scale-up">
                  <h4 className="font-bold text-slate-900 mb-4 flex items-center space-x-2">
                    <Mail size={18} className="text-blue-600" />
                    <span>Send Quote to Email</span>
                  </h4>
                  <div className="space-y-4">
                    <input 
                      required
                      type="email" 
                      placeholder="Enter your email address..."
                      className="w-full bg-white border border-slate-300 rounded-xl px-4 py-3 text-slate-900 focus:ring-2 focus:ring-blue-500 outline-none"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                    />
                    <div className="flex gap-2">
                       <button 
                        type="submit"
                        className="flex-grow bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-md"
                      >
                        Confirm & Save
                      </button>
                      <button 
                        type="button"
                        onClick={() => setIsSaving(false)}
                        className="px-4 bg-white border border-slate-200 text-slate-500 rounded-xl hover:bg-slate-100"
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                </form>
              ) : (
                <div className="flex gap-3 mb-8">
                  <button 
                    onClick={() => setIsSaving(true)}
                    className="flex-grow bg-slate-100 hover:bg-blue-600 hover:text-white text-slate-700 font-bold py-4 rounded-2xl transition-all flex items-center justify-center space-x-2 group"
                  >
                    <Save size={18} className="group-hover:scale-110 transition-transform" />
                    <span>Save My Quote</span>
                  </button>
                </div>
              )}

              {moveDate && (
                <div className="mb-8 p-4 bg-blue-50 rounded-2xl flex items-center space-x-3 border border-blue-100">
                  <Calendar className="text-blue-600" size={20} />
                  <div>
                    <p className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Planned Departure</p>
                    <p className="text-slate-900 font-bold">{new Date(moveDate).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
                  </div>
                </div>
              )}

              <div className="space-y-4 mb-10 border-t border-slate-100 pt-8">
                <p className="font-bold text-slate-900 flex items-center space-x-2">
                  <ListChecks size={18} className="text-blue-600" />
                  <span>Optional Protection & Services:</span>
                </p>
                <div className="grid grid-cols-1 gap-3">
                  {CALCULATOR_OPTIONS.services.map(service => (
                    <label key={service.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl cursor-pointer hover:bg-slate-100 transition-colors group">
                      <div className="flex items-center space-x-4">
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${extras.includes(service.id) ? 'bg-blue-600 border-blue-600' : 'border-slate-300'}`}>
                          {extras.includes(service.id) && <Plus size={12} className="text-white" />}
                        </div>
                        <span className="font-medium text-slate-700">{service.label}</span>
                      </div>
                      <input type="checkbox" className="hidden" checked={extras.includes(service.id)} onChange={() => toggleExtra(service.id)} />
                      <span className="text-slate-400 text-sm font-bold group-hover:text-blue-600">
                        {service.id === 'packing' ? `+£${Math.round(totalVolume * 50)}` : `+£${service.price}`}
                      </span>
                    </label>
                  ))}
                </div>
              </div>

              <button 
                onClick={onRequestFullQuote}
                className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold text-lg hover:bg-blue-600 transition-all transform hover:scale-[1.02] shadow-xl flex items-center justify-center space-x-3"
              >
                <span>Book Free Video Survey</span>
                <ArrowRight size={20} />
              </button>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255, 255, 255, 0.05); }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255, 255, 255, 0.2); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255, 255, 255, 0.3); }
      `}</style>
    </section>
  );
};

export default QuickQuoteCalculator;

import React, { useState, useEffect } from 'react';
import { 
  Lock, CheckCircle2, Truck, ClipboardList, MessageSquare, 
  Calendar, FileText, Send, Plus, Trash2, AlertCircle, 
  ChevronRight, MapPin, Package, ShieldCheck, UserCircle, History, ExternalLink,
  Upload, FileCheck, File, X, Loader2, Clock, Save
} from 'lucide-react';

interface CustomsItem {
  id: string;
  description: string;
  value: string;
  boxNumber?: string;
}

interface Message {
  id: string;
  text: string;
  sender: 'client' | 'agent';
  timestamp: string;
}

interface SavedQuote {
  ref: string;
  email: string;
  volume: number;
  price: number;
  date: string;
  status: string;
  origin: string;
  destination: string;
  customsList?: CustomsItem[];
}

interface UserDocument {
  id: string;
  name: string;
  status: 'required' | 'pending' | 'approved' | 'rejected';
  fileName?: string;
  uploadDate?: string;
}

const YourMove: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [reference, setReference] = useState('');
  const [surname, setSurname] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [activeMoveData, setActiveMoveData] = useState<SavedQuote | null>(null);
  const [activeTab, setActiveTab] = useState<'overview' | 'customs' | 'documents' | 'messages'>('overview');

  // Synced state for customs list
  const [itinerary, setItinerary] = useState<CustomsItem[]>([]);
  const [newItem, setNewItem] = useState({ description: '', value: '', boxNumber: '' });
  const [isSavingCustoms, setIsSavingCustoms] = useState(false);

  const [messages, setMessages] = useState<Message[]>([
    { id: '1', sender: 'agent', text: 'Hello! Welcome to your move portal. I am your coordinator, Mark. We have confirmed your loading for the 15th.', timestamp: '10:15 AM' },
    { id: '2', sender: 'client', text: 'Thank you Mark. Can I update the customs list until tomorrow?', timestamp: '11:20 AM' },
    { id: '3', sender: 'agent', text: 'Yes, of course. Please ensure all values are in GBP for the T1 document.', timestamp: '11:25 AM' },
  ]);
  const [newMessage, setNewMessage] = useState('');

  const [documents, setDocuments] = useState<UserDocument[]>([
    { id: 'doc-1', name: 'Lead Passenger Passport', status: 'required' },
    { id: 'doc-2', name: 'T1 Customs Declaration Form', status: 'required' },
    { id: 'doc-3', name: 'Spanish Residency Proof (TIE/NIE)', status: 'required' },
    { id: 'doc-4', name: 'Proof of UK Address (Council Tax/Utility)', status: 'required' },
  ]);
  const [isUploading, setIsUploading] = useState<string | null>(null);

  useEffect(() => {
    if (activeMoveData) {
      setItinerary(activeMoveData.customsList || []);
    }
  }, [activeMoveData]);

  const persistCustomsChanges = (updatedList: CustomsItem[]) => {
    if (!activeMoveData) return;
    const allQuotes = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
    const newQuotes = allQuotes.map((q: SavedQuote) => q.ref === activeMoveData.ref ? { ...q, customsList: updatedList } : q);
    localStorage.setItem('britons_saved_quotes', JSON.stringify(newQuotes));
    setActiveMoveData({ ...activeMoveData, customsList: updatedList });

    // Visual feedback for save
    setIsSavingCustoms(true);
    setTimeout(() => setIsSavingCustoms(false), 1000);
  };

  const updateItemInline = (id: string, field: keyof CustomsItem, value: string) => {
    const updated = itinerary.map(item => item.id === id ? { ...item, [field]: value } : item);
    setItinerary(updated);
    persistCustomsChanges(updated);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    setTimeout(() => {
      const savedQuotes: SavedQuote[] = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
      const foundQuote = savedQuotes.find(q => q.ref.toUpperCase() === reference.toUpperCase());

      if (reference.toUpperCase() === 'ESP-12345' || foundQuote) {
        if (foundQuote) {
          setActiveMoveData(foundQuote);
        } else {
          // Mock move if using the demo reference
          setActiveMoveData({
            ref: 'ESP-12345',
            email: 'demo@example.com',
            volume: 15,
            price: 3400,
            date: '2024-05-15',
            status: 'In Preparation',
            origin: 'London, UK',
            destination: 'Madrid, Spain',
            customsList: [
              { id: '1', description: 'Kitchenware (Standard Boxes)', value: '£400', boxNumber: '1-4' },
              { id: '2', description: 'Dining Room Table (Wrapped)', value: '£800', boxNumber: '7' },
            ]
          });
        }
        setIsAuthenticated(true);
      } else {
        setError('Reference not found. Please check your quote email.');
      }
      setLoading(false);
    }, 1200);
  };

  const handleAddItem = () => {
    if (newItem.description && newItem.value) {
      const updatedList = [...itinerary, { ...newItem, id: Date.now().toString() }];
      setItinerary(updatedList);
      persistCustomsChanges(updatedList);
      setNewItem({ description: '', value: '', boxNumber: '' });
    }
  };

  const removeItem = (id: string) => {
    const updatedList = itinerary.filter(i => i.id !== id);
    setItinerary(updatedList);
    persistCustomsChanges(updatedList);
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (newMessage.trim()) {
      const msg: Message = {
        id: Date.now().toString(),
        sender: 'client',
        text: newMessage,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };
      setMessages([...messages, msg]);
      setNewMessage('');
    }
  };

  const handleFileUpload = (docId: string, event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsUploading(docId);
    setTimeout(() => {
      setDocuments(prev => prev.map(doc => {
        if (doc.id === docId) {
          return { ...doc, status: 'pending', fileName: file.name, uploadDate: new Date().toLocaleDateString() };
        }
        return doc;
      }));
      setIsUploading(null);
    }, 1500);
  };

  const removeFile = (docId: string) => {
    setDocuments(prev => prev.map(doc => {
      if (doc.id === docId) return { ...doc, status: 'required', fileName: undefined, uploadDate: undefined };
      return doc;
    }));
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center bg-slate-50 px-4 py-12">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 border border-slate-100">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4"><Lock size={32} /></div>
            <h2 className="text-3xl font-bold text-slate-900">Your Move Portal</h2>
            <p className="text-slate-500 mt-2 text-sm">Enter your quote reference or move ID</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Move Reference</label>
              <input required type="text" placeholder="e.g. ESP-12345" className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all ${error ? 'border-red-500' : 'border-slate-200'}`} value={reference} onChange={(e) => setReference(e.target.value)} />
              {error && <p className="text-red-500 text-[10px] font-bold mt-1 uppercase tracking-wider">{error}</p>}
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Lead Surname / Email</label>
              <input required type="text" placeholder="Enter your registered name" className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" value={surname} onChange={(e) => setSurname(e.target.value)} />
            </div>
            <button type="submit" disabled={loading} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2">
              {loading ? <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <><span className="text-white">Access Dashboard</span><ChevronRight size={18} className="text-white"/></>}
            </button>
          </form>
          <div className="mt-8 p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200"><p className="text-[10px] text-slate-400 font-bold uppercase text-center mb-2">Helpful Tip</p><p className="text-[10px] text-slate-600 leading-relaxed text-center">Don't have a reference? Use the <span className="text-blue-600 font-bold">Quick Quote Calculator</span> and click 'Save Quote' to generate a reference instantly.</p></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <div className="bg-slate-900 text-white pt-12 pb-24">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center space-x-3 text-blue-400 text-sm font-bold uppercase tracking-widest mb-2"><Truck size={16} /><span>Reference: {reference || activeMoveData?.ref}</span></div>
              <h2 className="text-4xl font-black">Hello, {surname || 'Valued Customer'}</h2>
              <p className="text-slate-400 mt-2">Your relocation to <span className="text-white font-bold">{activeMoveData?.destination || 'Spain'}</span> is {activeMoveData?.status.toLowerCase() === 'quote saved' ? 'ready for booking.' : 'currently in progress.'}</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="bg-white/10 p-4 rounded-2xl border border-white/10 backdrop-blur-md">
                 <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-1">Target Date</p><p className="text-xl font-black">{activeMoveData?.date ? new Date(activeMoveData.date).toLocaleDateString() : 'TBC'}</p>
              </div>
              <div className="bg-blue-600 p-4 rounded-2xl border border-blue-500 shadow-xl">
                 <p className="text-xs text-blue-100 font-bold uppercase tracking-widest mb-1">Status</p><p className="text-xl font-black">{activeMoveData?.status || 'Active'}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-12">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden min-h-[600px] flex flex-col md:flex-row">
          <div className="w-full md:w-64 bg-slate-50 border-r border-slate-100 p-6 space-y-2">
            <button onClick={() => setActiveTab('overview')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><Package size={20} /><span>Overview</span></button>
            <button onClick={() => setActiveTab('customs')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'customs' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><ClipboardList size={20} /><span>Customs List</span></button>
            <button onClick={() => setActiveTab('documents')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'documents' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><FileCheck size={20} /><span>Documents</span></button>
            <button onClick={() => setActiveTab('messages')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'messages' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><MessageSquare size={20} /><span>Messages</span></button>
            <div className="pt-8 mt-8 border-t border-slate-200"><p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-4 px-4">Contact Agent</p><div className="px-4 py-3 bg-white rounded-xl border border-slate-100 shadow-sm flex items-center space-x-3"><div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600"><UserCircle size={20} /></div><div><p className="text-sm font-bold text-slate-800">Mark Collins</p><p className="text-[10px] text-slate-500">Coordinator</p></div></div></div>
            <button onClick={() => setIsAuthenticated(false)} className="w-full mt-12 text-xs font-bold text-slate-400 hover:text-red-500 text-left px-4">Log Out of Portal</button>
          </div>

          <div className="flex-grow p-6 md:p-10">
            {activeTab === 'overview' && (
              <div className="space-y-8 animate-fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-6">
                    <h3 className="text-2xl font-bold text-slate-900">Your Move Progress</h3>
                    <div className="space-y-4">
                      <div className="flex items-center space-x-4 p-4 bg-green-50 rounded-2xl border border-green-100"><div className="bg-green-500 text-white p-2 rounded-lg"><CheckCircle2 size={20} /></div><div><p className="font-bold text-slate-900">Quote Received</p><p className="text-xs text-slate-500">Completed via Web Calculator</p></div></div>
                      <div className={`flex items-center space-x-4 p-4 rounded-2xl border transition-all ${itinerary.length > 0 ? 'bg-green-50 border-green-100' : 'bg-blue-50 border-blue-100'}`}><div className={`${itinerary.length > 0 ? 'bg-green-500' : 'bg-blue-600'} text-white p-2 rounded-lg`}><ClipboardList size={20} /></div><div><p className="font-bold text-slate-900">Customs Declaration</p><p className="text-xs text-slate-500">{itinerary.length > 0 ? `${itinerary.length} items declared` : 'Please start your inventory list'}</p></div></div>
                    </div>
                  </div>
                  <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100">
                    <h3 className="text-xl font-bold text-slate-900 mb-6 flex items-center space-x-2"><MapPin size={18} className="text-blue-600" /><span>Key Details</span></h3>
                    <div className="space-y-4">
                      <div className="flex justify-between border-b border-slate-200 pb-2"><span className="text-slate-500 text-sm">Origin</span><span className="font-bold text-slate-900">{activeMoveData?.origin}</span></div>
                      <div className="flex justify-between border-b border-slate-200 pb-2"><span className="text-slate-500 text-sm">Destination</span><span className="font-bold text-slate-900">{activeMoveData?.destination}</span></div>
                      <div className="flex justify-between border-b border-slate-200 pb-2"><span className="text-slate-500 text-sm">Volume</span><span className="font-bold text-slate-900">{activeMoveData?.volume} m³</span></div>
                      <div className="flex justify-between"><span className="text-slate-500 text-sm">Estimated Total</span><span className="font-bold text-blue-600 text-lg">£{activeMoveData?.price.toLocaleString()}</span></div>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'customs' && (
              <div className="space-y-8 animate-fade-in">
                <div className="flex justify-between items-center">
                  <div>
                    <h3 className="text-2xl font-bold text-slate-900">Customs Itinerary (T1 Document)</h3>
                    <p className="text-xs text-slate-500 mt-1 font-bold flex items-center gap-2">
                       {itinerary.length > 0 && itinerary.every(i => i.value !== '') ? (
                          <span className="text-green-600 flex items-center gap-1 uppercase tracking-widest"><CheckCircle2 size={12}/> Manifest Ready for Review</span>
                       ) : itinerary.length === 0 ? (
                          <span className="text-slate-400 flex items-center gap-1 uppercase tracking-widest">Inventory list empty</span>
                       ) : (
                          <span className="text-amber-600 flex items-center gap-1 uppercase tracking-widest"><AlertCircle size={12}/> Please refine values for items</span>
                       )}
                       {isSavingCustoms && <><Loader2 size={12} className="animate-spin text-blue-600"/> <span className="text-blue-600 uppercase tracking-widest ml-1">Changes Saved</span></>}
                    </p>
                  </div>
                  <button className="bg-slate-900 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center space-x-2 shadow-lg hover:bg-slate-800 transition-colors">
                    <FileText size={16} /><span>Preview T1 Manifest</span>
                  </button>
                </div>

                <div className="overflow-x-auto rounded-2xl border border-slate-200 shadow-sm bg-white">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 text-slate-500 text-[10px] uppercase tracking-widest font-black">
                      <tr>
                        <th className="px-6 py-4">Item Description</th>
                        <th className="px-6 py-4">Est. Value (GBP)</th>
                        <th className="px-6 py-4 w-32">Box No.</th>
                        <th className="px-6 py-4 text-center">Action</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {itinerary.length === 0 && (
                        <tr>
                          <td colSpan={4} className="px-6 py-20 text-center">
                             <div className="flex flex-col items-center justify-center opacity-40">
                                <ClipboardList size={48} className="mb-4" />
                                <p className="font-bold text-lg">No Items Declared</p>
                                <p className="text-xs max-w-xs mx-auto mt-2 leading-relaxed">
                                   Please list all household goods you intend to move. 
                                   Accurate values and box counts are required for Spanish Customs (T1/T2).
                                </p>
                             </div>
                          </td>
                        </tr>
                      )}
                      {itinerary.map(item => (
                        <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
                          <td className="px-6 py-4">
                            <input 
                              type="text" 
                              value={item.description} 
                              onChange={(e) => updateItemInline(item.id, 'description', e.target.value)}
                              className="w-full bg-transparent border-none text-sm font-bold text-slate-900 focus:ring-0 p-0"
                            />
                          </td>
                          <td className="px-6 py-4">
                            <div className="flex items-center space-x-1">
                               <span className="text-slate-400 font-bold">£</span>
                               <input 
                                  type="text" 
                                  placeholder="0.00" 
                                  value={item.value} 
                                  onChange={(e) => updateItemInline(item.id, 'value', e.target.value)}
                                  className={`w-24 bg-transparent border-b ${item.value === '' ? 'border-amber-200 bg-amber-50/30' : 'border-transparent'} text-sm font-bold text-slate-900 focus:ring-0 p-0.5 focus:border-blue-500 transition-colors`}
                               />
                            </div>
                          </td>
                          <td className="px-6 py-4">
                            <input 
                              type="text" 
                              placeholder="e.g. 1" 
                              value={item.boxNumber} 
                              onChange={(e) => updateItemInline(item.id, 'boxNumber', e.target.value)}
                              className="w-full bg-transparent border-none text-sm font-mono text-slate-600 focus:ring-0 p-0"
                            />
                          </td>
                          <td className="px-6 py-4 text-center">
                            <button onClick={() => removeItem(item.id)} className="text-slate-300 hover:text-red-500 transition-colors p-2 opacity-0 group-hover:opacity-100" title="Remove item">
                              <Trash2 size={16} />
                            </button>
                          </td>
                        </tr>
                      ))}
                      <tr className="bg-blue-50/30">
                        <td className="px-6 py-4">
                          <input type="text" placeholder="Add additional item..." className="bg-transparent border-none outline-none w-full text-sm font-bold placeholder:text-blue-300" value={newItem.description} onChange={(e) => setNewItem({...newItem, description: e.target.value})} />
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center space-x-1">
                             <span className="text-blue-300 font-bold">£</span>
                             <input type="text" placeholder="Value" className="bg-transparent border-none outline-none w-full text-sm font-bold placeholder:text-blue-300" value={newItem.value} onChange={(e) => setNewItem({...newItem, value: e.target.value})} />
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <input type="text" placeholder="Box #" className="bg-transparent border-none outline-none w-full text-sm font-mono placeholder:text-blue-300" value={newItem.boxNumber} onChange={(e) => setNewItem({...newItem, boxNumber: e.target.value})} />
                        </td>
                        <td className="px-6 py-4 text-center">
                          <button onClick={handleAddItem} className="bg-blue-600 text-white p-2.5 rounded-xl shadow-lg hover:bg-blue-700 transition-all flex items-center justify-center">
                             <Plus size={18} />
                          </button>
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </div>

                {itinerary.length > 0 ? (
                  <div className="p-4 bg-green-50 border border-green-100 rounded-xl flex items-center space-x-3">
