                                         <div className="col-span-6"><input type="text" value={item.description} onChange={(e) => setEditingCustoms(editingCustoms.map(i => i.id === item.id ? { ...i, description: e.target.value } : i))} className="w-full bg-transparent border-none text-xs font-bold text-slate-800 focus:ring-0" /></div>
                                         <div className="col-span-3"><input type="text" value={item.value} onChange={(e) => setEditingCustoms(editingCustoms.map(i => i.id === item.id ? { ...i, value: e.target.value } : i))} className="w-full bg-transparent border-none text-xs font-medium text-slate-600 focus:ring-0" /></div>
                                         <div className="col-span-2"><input type="text" value={item.boxNumber} onChange={(e) => setEditingCustoms(editingCustoms.map(i => i.id === item.id ? { ...i, boxNumber: e.target.value } : i))} className="w-full bg-transparent border-none text-xs font-mono text-slate-400 focus:ring-0" /></div>
                                         <div className="col-span-1 flex justify-end"><button onClick={() => removeCustomsItem(item.id)} className="p-1.5 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={14} /></button></div>
                                      </div>
                                   ))}

                                   <div className="grid grid-cols-12 gap-2 bg-blue-50/30 p-2 rounded-xl items-center border border-dashed border-blue-200">
                                      <div className="col-span-6"><input type="text" placeholder="Add additional line..." value={newCustomsItem.description} onChange={(e) => setNewCustomsItem({...newCustomsItem, description: e.target.value})} className="w-full bg-transparent border-none text-xs font-bold text-slate-800 placeholder:text-blue-300 focus:ring-0" /></div>
                                      <div className="col-span-3"><input type="text" placeholder="Value" value={newCustomsItem.value} onChange={(e) => setNewCustomsItem({...newCustomsItem, value: e.target.value})} className="w-full bg-transparent border-none text-xs text-slate-600 placeholder:text-blue-300 focus:ring-0" /></div>
                                      <div className="col-span-2"><input type="text" placeholder="Box" value={newCustomsItem.boxNumber} onChange={(e) => setNewCustomsItem({...newCustomsItem, boxNumber: e.target.value})} className="w-full bg-transparent border-none text-xs font-mono text-slate-400 placeholder:text-blue-300 focus:ring-0" /></div>
                                      <div className="col-span-1 flex justify-end"><button onClick={addCustomsItem} className="p-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"><Plus size={14} /></button></div>
                                   </div>
                                </div>
                                {editingCustoms.length === 0 && <p className="text-center py-20 text-xs text-slate-400 font-bold uppercase italic tracking-widest">No items listed in manifest</p>}
                             </div>
                          </div>
                       )}

                       {modalTab === 'chat' && (
                          <div className="flex flex-col h-full animate-fade-in bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                             <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50">
                                <h4 className="font-black text-slate-900 flex items-center gap-2"><UserCircle size={18} className="text-blue-600"/><span>Chat with {selectedQuote.email}</span></h4>
                                <span className="text-[10px] font-black text-green-600 uppercase bg-green-100 px-2 py-1 rounded-full">Secure Session</span>
                             </div>

                             <div className="flex-grow overflow-y-auto p-6 space-y-4 custom-scrollbar">
                                {adminMessages.length === 0 && (
                                   <div className="flex flex-col items-center justify-center h-full opacity-40">
                                      <MessageSquare size={48} className="mb-4" />
                                      <p className="font-bold">No messages yet.</p>
                                      <p className="text-xs">Send a greeting to start the conversation.</p>
                                   </div>
                                )}
                                {adminMessages.map(msg => (
                                   <div key={msg.id} className={`flex flex-col ${msg.sender === 'agent' ? 'items-end' : 'items-start'}`}>
                                      <div className={`max-w-[70%] px-4 py-2.5 rounded-2xl text-sm shadow-sm ${msg.sender === 'agent' ? 'bg-blue-600 text-white rounded-br-none' : 'bg-slate-100 text-slate-800 rounded-bl-none'}`}>
                                         {msg.text}
                                      </div>
                                      <span className="text-[9px] text-slate-400 mt-1 font-bold">{msg.timestamp} • {msg.sender === 'agent' ? 'You' : 'Client'}</span>
                                   </div>
                                ))}
                             </div>

                             <form onSubmit={sendAdminMessage} className="p-4 bg-slate-50 border-t border-slate-200 flex items-center gap-3">
                                <input 
                                   type="text" 
                                   placeholder="Type a message to the client..." 
                                   className="flex-grow bg-white border border-slate-200 px-4 py-3 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                                   value={adminNewMessage}
                                   onChange={(e) => setAdminNewMessage(e.target.value)}
                                />
                                <button type="submit" className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg flex items-center justify-center">
                                   <Send size={20} />
                                </button>
                             </form>
                          </div>
                       )}
                    </div>
                 </div>
              </div>

              <div className="p-8 bg-white border-t border-slate-100 flex gap-4 shrink-0 justify-between items-center">
                 <div className="flex gap-4">
                    <button className="bg-slate-900 text-white px-8 py-4 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2 shadow-lg">
                       <Download size={18} /><span>Download PDF Dossier</span>
                    </button>
                 </div>
                 <button onClick={() => setSelectedQuote(null)} className="px-10 py-4 bg-slate-50 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-100 transition-all">Close Admin View</button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default AdminPortal;

import React, { useState, useEffect } from 'react';
import { 
  Lock, CheckCircle2, Truck, ClipboardList, MessageSquare, 
  Calendar, FileText, Send, Plus, Trash2, AlertCircle, 
  ChevronRight, MapPin, Package, ShieldCheck, UserCircle, History, ExternalLink,
  Upload, FileCheck, File, X, Loader2, Clock, Save
} from 'lucide-react';

interface Message {
  id: string;
  text: string;
  sender: 'client' | 'agent';
  timestamp: string;
}

interface CustomsItem {
  id: string;
  description: string;
  value: string;
  boxNumber?: string;
}

interface SavedQuote {
  ref: string;
  email: string;
  volume: number;
  price: number;
  date: string;
  status: string;
  origin: string;
  destination: string;
  customsList?: CustomsItem[];
  messages?: Message[];
}

interface UserDocument {
  id: string;
  name: string;
  status: 'required' | 'pending' | 'approved' | 'rejected';
  fileName?: string;
  uploadDate?: string;
}

const YourMove: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [reference, setReference] = useState('');
  const [surname, setSurname] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [activeMoveData, setActiveMoveData] = useState<SavedQuote | null>(null);
  const [activeTab, setActiveTab] = useState<'overview' | 'customs' | 'documents' | 'messages'>('overview');

  // Synced state for customs list
  const [itinerary, setItinerary] = useState<CustomsItem[]>([]);
  const [newItem, setNewItem] = useState({ description: '', value: '', boxNumber: '' });
  const [isSavingCustoms, setIsSavingCustoms] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');

  const [documents, setDocuments] = useState<UserDocument[]>([
    { id: 'doc-1', name: 'Lead Passenger Passport', status: 'required' },
    { id: 'doc-2', name: 'T1 Customs Declaration Form', status: 'required' },
    { id: 'doc-3', name: 'Spanish Residency Proof (TIE/NIE)', status: 'required' },
    { id: 'doc-4', name: 'Proof of UK Address (Council Tax/Utility)', status: 'required' },
  ]);
  const [isUploading, setIsUploading] = useState<string | null>(null);

  useEffect(() => {
    if (activeMoveData) {
      setItinerary(activeMoveData.customsList || []);
      setMessages(activeMoveData.messages || []);
    }
  }, [activeMoveData]);

  const persistQuoteChanges = (updatedQuote: SavedQuote) => {
    const allQuotes = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
    const newQuotes = allQuotes.map((q: SavedQuote) => q.ref === updatedQuote.ref ? updatedQuote : q);
    localStorage.setItem('britons_saved_quotes', JSON.stringify(newQuotes));
    setActiveMoveData(updatedQuote);
  };

  const persistCustomsChanges = (updatedList: CustomsItem[]) => {
    if (!activeMoveData) return;
    const updatedQuote = { ...activeMoveData, customsList: updatedList };
    persistQuoteChanges(updatedQuote);

    // Visual feedback for save
    setIsSavingCustoms(true);
    setTimeout(() => setIsSavingCustoms(false), 1000);
  };

  const updateItemInline = (id: string, field: keyof CustomsItem, value: string) => {
    const updated = itinerary.map(item => item.id === id ? { ...item, [field]: value } : item);
    setItinerary(updated);
    persistCustomsChanges(updated);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    setTimeout(() => {
      const savedQuotes: SavedQuote[] = JSON.parse(localStorage.getItem('britons_saved_quotes') || '[]');
      const foundQuote = savedQuotes.find(q => q.ref.toUpperCase() === reference.toUpperCase());

      if (reference.toUpperCase() === 'ESP-12345' || foundQuote) {
        if (foundQuote) {
          setActiveMoveData(foundQuote);
        } else {
          // Mock move if using the demo reference
          const demoQuote: SavedQuote = {
            ref: 'ESP-12345',
            email: 'demo@example.com',
            volume: 15,
            price: 3400,
            date: '2024-05-15',
            status: 'In Preparation',
            origin: 'London, UK',
            destination: 'Madrid, Spain',
            customsList: [
              { id: '1', description: 'Kitchenware (Standard Boxes)', value: '400', boxNumber: '1-4' },
              { id: '2', description: 'Dining Room Table (Wrapped)', value: '800', boxNumber: '7' },
            ],
            messages: [
              { id: '1', sender: 'agent', text: 'Hello! Welcome to your move portal. I am your coordinator, Mark. We have confirmed your loading for the 15th.', timestamp: '10:15 AM' }
            ]
          };
          setActiveMoveData(demoQuote);
        }
        setIsAuthenticated(true);
      } else {
        setError('Reference not found. Please check your quote email.');
      }
      setLoading(false);
    }, 1200);
  };

  const handleAddItem = () => {
    if (newItem.description && newItem.value) {
      const updatedList = [...itinerary, { ...newItem, id: Date.now().toString() }];
      setItinerary(updatedList);
      persistCustomsChanges(updatedList);
      setNewItem({ description: '', value: '', boxNumber: '' });
    }
  };

  const removeItem = (id: string) => {
    const updatedList = itinerary.filter(i => i.id !== id);
    setItinerary(updatedList);
    persistCustomsChanges(updatedList);
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (newMessage.trim() && activeMoveData) {
      const msg: Message = {
        id: Date.now().toString(),
        sender: 'client',
        text: newMessage,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };

      const updatedMessages = [...messages, msg];
      setMessages(updatedMessages);

      const updatedQuote = { ...activeMoveData, messages: updatedMessages };
      persistQuoteChanges(updatedQuote);
      setNewMessage('');
    }
  };

  const handleFileUpload = (docId: string, event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsUploading(docId);
    setTimeout(() => {
      setDocuments(prev => prev.map(doc => {
        if (doc.id === docId) {
          return { ...doc, status: 'pending', fileName: file.name, uploadDate: new Date().toLocaleDateString() };
        }
        return doc;
      }));
      setIsUploading(null);
    }, 1500);
  };

  const removeFile = (docId: string) => {
    setDocuments(prev => prev.map(doc => {
      if (doc.id === docId) return { ...doc, status: 'required', fileName: undefined, uploadDate: undefined };
      return doc;
    }));
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center bg-slate-50 px-4 py-12">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-8 md:p-12 border border-slate-100">
          <div className="text-center mb-8">
            <div className="mb-6">
              <img src="logo.png" alt="Logo" className="h-12 w-auto mx-auto object-contain" />
            </div>
            <h2 className="text-3xl font-bold text-slate-900">Your Move Portal</h2>
            <p className="text-slate-500 mt-2 text-sm">Enter your quote reference or move ID</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Move Reference</label>
              <input required type="text" placeholder="e.g. ESP-12345" className={`w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all ${error ? 'border-red-500' : 'border-slate-200'}`} value={reference} onChange={(e) => setReference(e.target.value)} />
              {error && <p className="text-red-500 text-[10px] font-bold mt-1 uppercase tracking-wider">{error}</p>}
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide">Lead Surname / Email</label>
              <input required type="text" placeholder="Enter your registered name" className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" value={surname} onChange={(e) => setSurname(e.target.value)} />
            </div>
            <button type="submit" disabled={loading} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg transition-all flex items-center justify-center space-x-2">
              {loading ? <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <><span className="text-white">Access Dashboard</span><ChevronRight size={18} className="text-white"/></>}
            </button>
          </form>
          <div className="mt-8 p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200"><p className="text-[10px] text-slate-400 font-bold uppercase text-center mb-2">Helpful Tip</p><p className="text-[10px] text-slate-600 leading-relaxed text-center">Don't have a reference? Use the <span className="text-blue-600 font-bold">Quick Quote Calculator</span> and click 'Save Quote' to generate a reference instantly.</p></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <div className="bg-slate-900 text-white pt-12 pb-24">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center space-x-3 text-blue-400 text-sm font-bold uppercase tracking-widest mb-2"><Truck size={16} /><span>Reference: {reference || activeMoveData?.ref}</span></div>
              <h2 className="text-4xl font-black">Hello, {surname || 'Valued Customer'}</h2>
              <p className="text-slate-400 mt-2">Your relocation to <span className="text-white font-bold">{activeMoveData?.destination || 'Spain'}</span> is {activeMoveData?.status.toLowerCase() === 'quote saved' ? 'ready for booking.' : 'currently in progress.'}</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="bg-white/10 p-4 rounded-2xl border border-white/10 backdrop-blur-md">
                 <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-1">Target Date</p><p className="text-xl font-black">{activeMoveData?.date ? new Date(activeMoveData.date).toLocaleDateString() : 'TBC'}</p>
              </div>
              <div className="bg-blue-600 p-4 rounded-2xl border border-blue-500 shadow-xl">
                 <p className="text-xs text-blue-100 font-bold uppercase tracking-widest mb-1">Status</p><p className="text-xl font-black">{activeMoveData?.status || 'Active'}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-12">
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden min-h-[600px] flex flex-col md:flex-row">
          <div className="w-full md:w-64 bg-slate-50 border-r border-slate-100 p-6 space-y-2">
            <button onClick={() => setActiveTab('overview')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><Package size={20} /><span>Overview</span></button>
            <button onClick={() => setActiveTab('customs')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'customs' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><ClipboardList size={20} /><span>Customs List</span></button>
            <button onClick={() => setActiveTab('documents')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'documents' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><FileCheck size={20} /><span>Documents</span></button>
            <button onClick={() => setActiveTab('messages')} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === 'messages' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-600 hover:bg-slate-200'}`}><MessageSquare size={20} /><span>Messages</span></button>
            <div className="pt-8 mt-8 border-t border-slate-200"><p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-4 px-4">Contact Agent</p><div className="px-4 py-3 bg-white rounded-xl border border-slate-100 shadow-sm flex items-center space-x-3"><div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-blue-600"><UserCircle size={20} /></div><div><p className="text-sm font-bold text-slate-800">Mark Collins</p><p className="text-[10px] text-slate-500">Coordinator</p></div></div></div>
            <button onClick={() => setIsAuthenticated(false)} className="w-full mt-12 text-xs font-bold text-slate-400 hover:text-red-500 text-left px-4">Log Out of Portal</button>
          </div>

          <div className="flex-grow p-6 md:p-10">
            {activeTab === 'overview' && (
              <div className="space-y-8 animate-fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-6">
                    <h3 className="text-2xl font-bold text-slate-900">Your Move Progress</h3>
                    <div className="space-y-4">
                      <div className="flex items-center space-x-4 p-4 bg-green-50 rounded-2xl border border-green-100"><div className="bg-green-500 text-white p-2 rounded-lg"><CheckCircle2 size={20} /></div><div><p className="font-bold text-slate-900">Quote Received</p><p className="text-xs text-slate-500">Completed via Web Calculator</p></div></div>
